import { Card, Stack, Row, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Maps weather condition text to appropriate emoji
 */
function getWeatherEmoji(condition: string): string {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️';
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 72, low: 60 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☁️', high: 70, low: 59 },
    { day: 'Fri', icon: '☀️', high: 76, low: 63 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
        maxWidth: '500px',
        margin: '0 auto',
      }}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header: City and Condition */}
        <Row gap={12} align="center" justify="between">
          <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Row>

        {/* Current Weather: Temperature and Emoji */}
        <Row gap={24} align="center" justify="center">
          <Stack direction="vertical" align="center" gap={8}>
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{
                fontSize: '56px',
                lineHeight: '1.1',
              }}
            >
              {temperature}
              {unit}
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>

          {/* Large Weather Emoji */}
          <div
            style={{
              fontSize: '80px',
              lineHeight: '1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {weatherEmoji}
          </div>
        </Row>

        {/* Metrics Section: Humidity and Wind Speed */}
        <Row gap={24} justify="around" align="center">
          <Stack direction="vertical" align="center" gap={4}>
            <Text
              variant="caption"
              weight="semibold"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" align="center" gap={4}>
            <Text
              variant="caption"
              weight="semibold"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} mph
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <Divider orientation="horizontal" margin={12} />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={8}>
          <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Text>

          <Row
            gap={8}
            justify="between"
            align="stretch"
            wrap={false}
            style={{
              overflowX: 'auto',
              paddingBottom: '8px',
            }}
          >
            {forecast.map((item, index) => (
              <Box
                key={item.day || `day-${index}`}
                padding={12}
                background="var(--ggui-color-surface, #fafafa)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  flex: '1 1 auto',
                  minWidth: '80px',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  textAlign: 'center',
                }}
              >
                <Stack direction="vertical" align="center" gap={6}>
                  {/* Day Name */}
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {item.day || `Day ${index + 1}`}
                  </Text>

                  {/* Weather Icon */}
                  <div style={{ fontSize: '28px', lineHeight: '1' }}>
                    {item.icon || getWeatherEmoji('Sunny')}
                  </div>

                  {/* High Temperature */}
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {item.high}°
                  </Text>

                  {/* Low Temperature */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { Container, Card, Stack, Row, Text, Button, Input, Select, Badge, Icon, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  column: string;
  dueDate?: string;
}

interface Column {
  id: string;
  name: string;
}

interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

const AvatarInitials = ({ initials }: { initials?: string }) => {
  if (!initials) return null;
  return <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 32, height: 32, borderRadius: '50%', backgroundColor: 'var(--ggui-color-container, #ede9fe)', color: 'var(--ggui-color-onContainer, #4c1d95)', fontSize: 'var(--ggui-font-size-sm, 14px)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }} title={`Assigned to ${initials}`} role="img" aria-label={`Assigned to ${initials}`}>{initials.substring(0, 2).toUpperCase()}</div>;
};

const TaskCard = (props: { task: Task; onEdit: (id: string) => void; onMove: (id: string, col: string) => void; editingTaskId: string | null; editingTitle: string; setEditingTitle: (v: string) => void; columns: Column[] }) => {
  const { motionEnabled } = useMotion();
  const getPriorityVariant = (p: string): 'primary' | 'warning' | 'error' => p === 'low' ? 'primary' : p === 'medium' ? 'warning' : 'error';
  const { task, onEdit, onMove, editingTaskId, editingTitle, setEditingTitle, columns } = props;

  if (editingTaskId === task.id) {
    return (
      <Card padding={12} border shadow="sm" style={{ animation: motionEnabled ? animation.slideInUp : 'none', backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
        <Stack direction="vertical" gap={8}>
          <Input label="Edit task title" placeholder="Task title" value={editingTitle} onChange={setEditingTitle} />
          <Row gap={8} justify="end">
            <Button size="sm" variant="ghost" onClick={() => { setEditingTitle(''); onEdit(''); }} aria-label="Cancel">Cancel</Button>
            <Button size="sm" variant="primary" onClick={() => editingTitle.trim() && onEdit(task.id)} aria-label="Save">Save</Button>
          </Row>
        </Stack>
      </Card>
    );
  }

  return (
    <Card padding={12} border shadow="sm" style={{ animation: motionEnabled ? animation.slideInUp : 'none', cursor: 'pointer', transition: 'box-shadow 200ms ease-out' }} onMouseEnter={(e) => { (e.currentTarget as HTMLElement).style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'; }} onMouseLeave={(e) => { (e.currentTarget as HTMLElement).style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'; }}>
      <Stack direction="vertical" gap={8}>
        <Row gap={8} align="start" justify="between">
          <Text variant="body" weight="normal" style={{ flex: 1, wordBreak: 'break-word' }} onDoubleClick={() => { onEdit(task.id); setEditingTitle(task.title); }} role="button" tabIndex={0} aria-label={`${task.title}. Double-click to edit.`}>{task.title}</Text>
          <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>{task.priority}</Badge>
        </Row>
        <Row gap={8} align="center">
          {task.assignee && <AvatarInitials initials={task.assignee} />}
          {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Due: {new Date(task.dueDate).toLocaleDateString()}</Text>}
        </Row>
        <Select label="Move to column" value={task.column} onChange={(col) => col !== task.column && onMove(task.id, col)} options={columns.filter((c) => c.id !== task.column).map((c) => ({ value: c.id, label: `Move to ${c.name}` }))} placeholder="Move to..." />
      </Stack>
    </Card>
  );
};

const AddTaskForm = (props: { columnId: string; onSubmit: (t: string, p: 'low' | 'medium' | 'high') => void; onCancel: () => void; isSubmitting: boolean; error: string }) => {
  const { columnId, onSubmit, onCancel, isSubmitting, error } = props;
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleSubmit = () => {
    if (!title.trim()) return;
    onSubmit(title, priority);
    setTitle('');
    setPriority('medium');
  };

  return (
    <Card padding={16} border shadow="sm" style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', borderColor: 'var(--ggui-color-primary-200, #bae6fd)' }}>
      <Stack direction="vertical" gap={12}>
        <Text variant="label" weight="semibold">New Task</Text>
        <Input label="Task title" placeholder="Enter task title" value={title} onChange={setTitle} required error={error} disabled={isSubmitting} />
        <Select label="Priority" value={priority} onChange={(v) => setPriority(v as 'low' | 'medium' | 'high')} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} disabled={isSubmitting} />
        <Row gap={8} justify="end">
          <Button variant="outline" size="sm" onClick={onCancel} disabled={isSubmitting}>Cancel</Button>
          <Button variant="primary" size="sm" onClick={handleSubmit} disabled={!title.trim() || isSubmitting} loading={isSubmitting}>{isSubmitting ? 'Adding...' : 'Add Task'}</Button>
        </Row>
      </Stack>
    </Card>
  );
};

const ColumnCard = (props: any) => {
  const { column, tasks, allColumns, onAddTask, onEditTask, onMoveTask, onShowAddForm, showAddForm, editingTaskId, editingTitle, setEditingTitle, isSubmitting, formError } = props;
  return (
    <Card padding={16} border shadow="sm" style={{ minWidth: 320, backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', flex: '0 0 320px' }}>
      <Stack direction="vertical" gap={12}>
        <Row justify="between" align="center">
          <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{column.name}</Text>
          <Badge variant="secondary" size="sm" title={`${tasks.length} tasks`}>{tasks.length}</Badge>
        </Row>
        <Divider orientation="horizontal" margin={8} />
        <Stack direction="vertical" gap={12} style={{ minHeight: '200px' }} role="region" aria-label={`${column.name} tasks`}>
          {tasks.map((task: Task) => (
            <TaskCard key={task.id} task={task} onEdit={onEditTask} onMove={onMoveTask} editingTaskId={editingTaskId} editingTitle={editingTitle} setEditingTitle={setEditingTitle} columns={allColumns} />
          ))}
        </Stack>
        {showAddForm === column.id ? (
          <AddTaskForm columnId={column.id} onSubmit={(t, p) => onAddTask(column.id, t, p)} onCancel={() => onShowAddForm(null)} isSubmitting={isSubmitting} error={formError[column.id] || ''} />
        ) : (
          <Button variant="outline" size="sm" fullWidth leftIcon={<Icon name="plus" size={16} />} onClick={() => onShowAddForm(column.id)} aria-label={`Add task to ${column.name}`}>Add Task</Button>
        )}
      </Stack>
    </Card>
  );
};

export default function KanbanBoard({ tasks: initialTasks, columns: initialColumns, onTaskUpdate }: Props) {
  const { motionEnabled } = useMotion();
  const columns = useMemo(() => initialColumns.filter((c) => c.id && c.name).map((c) => ({ id: c.id!, name: c.name! })), [initialColumns]);
  const [tasks, setTasks] = useState<Task[]>(() => initialTasks.filter((t) => t.id && t.title && t.column && columns.some((c) => c.id === t.column)).map((t) => ({ id: t.id!, title: t.title!, priority: t.priority || 'medium', assignee: t.assignee, column: t.column!, dueDate: t.dueDate })));
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formError, setFormError] = useState<Record<string, string>>({});
  const [successMessage, setSuccessMessage] = useState(false);

  useEffect(() => { setTasks(initialTasks.filter((t) => t.id && t.title && t.column && columns.some((c) => c.id === t.column)).map((t) => ({ id: t.id!, title: t.title!, priority: t.priority || 'medium', assignee: t.assignee, column: t.column!, dueDate: t.dueDate }))); }, [initialTasks, columns]);
  useEffect(() => { if (successMessage) { const timeout = setTimeout(() => setSuccessMessage(false), 2000); return () => clearTimeout(timeout); } }, [successMessage]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Task[]> = {};
    columns.forEach((col) => { grouped[col.id] = []; });
    tasks.forEach((task) => { if (grouped[task.column]) grouped[task.column].push(task); });
    return grouped;
  }, [tasks, columns]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === columns[columns.length - 1]?.id).length;

  const handleAddTask = (columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    if (!title.trim()) { setFormError({ ...formError, [columnId]: 'Task title is required' }); return; }
    setIsSubmitting(true);
    setFormError({});
    setTimeout(() => {
      const newTask: Task = { id: Math.random().toString(36).substring(2, 11), title: title.trim(), priority, column: columnId };
      setTasks((prev) => [...prev, newTask]);
      onTaskUpdate?.({ action: 'create', data: { title: newTask.title, priority: newTask.priority, column: columnId } });
      setShowAddForm(null);
      setIsSubmitting(false);
      setSuccessMessage(true);
    }, 300);
  };

  const handleEditTask = (taskId: string) => {
    if (editingTaskId === taskId && editingTitle.trim()) {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle.trim() } : t)));
      onTaskUpdate?.({ action: 'edit', taskId, data: { title: editingTitle.trim() } });
      setEditingTaskId(null);
      setEditingTitle('');
    } else if (editingTaskId === taskId) {
      setEditingTaskId(null);
      setEditingTitle('');
    } else {
      setEditingTaskId(taskId);
      const task = tasks.find((t) => t.id === taskId);
      if (task) setEditingTitle(task.title);
    }
  };

  const handleMoveTask = (taskId: string, toColumn: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t)));
    onTaskUpdate?.({ action: 'move', taskId, data: { toColumn } });
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={24} center={false}>
        <Stack direction="vertical" gap={24}>
          <Card padding={16} border shadow="sm" style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', borderColor: 'var(--ggui-color-primary-200, #bae6fd)' }}>
            <Row gap={24} justify="center" align="center">
              <Stack direction="vertical" gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total Tasks</Text>
                <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600, #0284c7)" role="status" aria-live="polite">{totalTasks}</Text>
              </Stack>
              <Divider orientation="vertical" margin={0} />
              <Stack direction="vertical" gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed</Text>
                <Text variant="h2" weight="bold" color="var(--ggui-color-success-500, #22c55e)" role="status" aria-live="polite">{completedTasks}</Text>
              </Stack>
            </Row>
          </Card>
          <div style={{ overflowX: 'auto', paddingBottom: 16 }} role="main">
            <Row gap={16} align="start" style={{ minWidth: 'max-content', paddingRight: 24 }}>
              {columns.map((column) => (
                <ColumnCard key={column.id} column={column} tasks={tasksByColumn[column.id] || []} allColumns={columns} onAddTask={handleAddTask} onEditTask={handleEditTask} onMoveTask={handleMoveTask} onShowAddForm={setShowAddForm} showAddForm={showAddForm} editingTaskId={editingTaskId} editingTitle={editingTitle} setEditingTitle={setEditingTitle} isSubmitting={isSubmitting} formError={formError} />
              ))}
            </Row>
          </div>
          {successMessage && (
            <Card padding={12} border shadow="sm" style={{ backgroundColor: 'var(--ggui-color-success-500, #22c55e)', color: 'white', textAlign: 'center', animation: motionEnabled ? animation.slideInUp : 'none' }} role="status" aria-live="polite">
              <Text color="white" weight="medium">✓ Task added successfully</Text>
            </Card>
          )}
        </Stack>
      </Container>
    </>
  );
}

