import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Input,
  Button,
  Divider,
  Icon,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const categoryColorMap: Record<string, string> = {
    'noble-gas': 'var(--ggui-color-primary-500, #0ea5e9)',
    'halogen': 'var(--ggui-color-warning-500, #f59e0b)',
    'alkali-metal': 'var(--ggui-color-error-500, #ef4444)',
    'alkaline-earth': 'var(--ggui-color-info-500, #06b6d4)',
    'transition-metal': 'var(--ggui-color-neutral-400, #9ca3af)',
    'lanthanide': 'var(--ggui-color-success-500, #22c55e)',
    'actinide': 'var(--ggui-color-secondary-500, #8b5cf6)',
    'nonmetal': 'var(--ggui-color-warning-300, #fcd34d)',
    'metalloid': 'var(--ggui-color-neutral-300, #d1d5db)',
    'post-transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
    'default': 'var(--ggui-color-neutral-100, #f3f4f6)',
  };

  const filteredElements = useMemo(() => {
    return elements.filter(el => {
      const query = searchQuery.toLowerCase();
      return (
        (el.name?.toLowerCase().includes(query) ?? false) ||
        (el.symbol?.toLowerCase().includes(query) ?? false)
      );
    });
  }, [searchQuery, elements]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set(elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [elements]);

  const getCategoryColor = (category?: string): string => {
    return categoryColorMap[category ?? ''] || categoryColorMap['default'];
  };

  const getTextColor = (): string => {
    return 'var(--ggui-color-onContainer, #4c1d95)';
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24}>
        <Stack direction="vertical" gap={8} align="center">
          <Text variant="h1" align="center" weight="bold">
            Periodic Table of Elements
          </Text>
          <Text
            variant="body"
            align="center"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Interactive periodic table with search and element details
          </Text>
        </Stack>

        <Stack direction="vertical" align="center" style={{ maxWidth: '400px', alignSelf: 'center' }}>
          <Input
            label="Search Elements"
            placeholder="Search by name or symbol..."
            value={searchQuery}
            onChange={setSearchQuery}
          />
        </Stack>

        <div
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: 'var(--ggui-spacing-4, 16px)',
            justifyContent: 'center',
            alignItems: 'center',
            padding: 'var(--ggui-spacing-4, 16px) 0',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          {uniqueCategories.map(category => (
            <div
              key={category}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-1, 6px)',
              }}
            >
              <div
                style={{
                  width: '16px',
                  height: '16px',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: getCategoryColor(category),
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                }}
              />
              <Text variant="caption" weight="medium">
                {(category || 'Unknown').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}
              </Text>
            </div>
          ))}
        </div>

        {filteredElements.length > 0 ? (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-2, 8px)',
              marginBottom: 'var(--ggui-spacing-6, 24px)',
              padding: 'var(--ggui-spacing-4, 16px)',
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            }}
          >
            {filteredElements.map(element => {
              const bgColor = getCategoryColor(element.category);
              const isSelected = selectedElement?.atomicNumber === element.atomicNumber;

              return (
                <button
                  key={element.atomicNumber}
                  onClick={() => setSelectedElement(element)}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                    backgroundColor: bgColor,
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    minHeight: '60px',
                    transition: 'all 200ms cubic-bezier(0, 0, 0.2, 1)',
                    boxShadow: isSelected
                      ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                      : 'none',
                    transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                    outline: 'none',
                    position: 'relative',
                  }}
                  onMouseEnter={(e) => {
                    if (!isSelected) {
                      const btn = e.currentTarget as HTMLElement;
                      btn.style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                      btn.style.transform = 'scale(1.05)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!isSelected) {
                      const btn = e.currentTarget as HTMLElement;
                      btn.style.boxShadow = 'none';
                      btn.style.transform = 'scale(1)';
                    }
                  }}
                  aria-label={`${element.name} (${element.symbol})`}
                  aria-pressed={isSelected}
                  type="button"
                >
                  <Text
                    variant="caption"
                    weight="semibold"
                    color={getTextColor()}
                    style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {element.atomicNumber}
                  </Text>

                  <Text
                    variant="h3"
                    weight="bold"
                    color={getTextColor()}
                    align="center"
                  >
                    {element.symbol}
                  </Text>

                  {element.name && (
                    <Text
                      variant="caption"
                      color={getTextColor()}
                      align="center"
                      style={{ fontSize: '10px', marginTop: 'var(--ggui-spacing-1, 2px)' }}
                    >
                      {element.name}
                    </Text>
                  )}
                </button>
              );
            })}
          </div>
        ) : (
          <div
            style={{
              padding: 'var(--ggui-spacing-8, 32px)',
              textAlign: 'center',
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            }}
          >
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              No elements found matching "{searchQuery}"
            </Text>
          </div>
        )}

        {selectedElement && (
          <Card
            padding={24}
            shadow="md"
            border
            style={{
              animation: 'slideInUp 200ms ease-out',
            }}
          >
            <Stack direction="vertical" gap={16}>
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <Text variant="h2" weight="bold">
                  {selectedElement.name}
                </Text>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                  rightIcon={<Icon name="x" size={18} />}
                >
                  Close
                </Button>
              </div>

              <Divider margin={0} />

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--ggui-spacing-4, 16px)' }}>
                <div>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Symbol
                  </Text>
                  <Text variant="h3" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                    {selectedElement.symbol}
                  </Text>
                </div>

                <div>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Atomic Number
                  </Text>
                  <Text variant="h3" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                    {selectedElement.atomicNumber}
                  </Text>
                </div>

                <div>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Atomic Weight
                  </Text>
                  <Text variant="body" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                    {selectedElement.atomicWeight?.toFixed(2) ?? 'N/A'}
                  </Text>
                </div>

                <div>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Category
                  </Text>
                  <div style={{ marginTop: 'var(--ggui-spacing-1, 4px)', display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 6px)' }}>
                    <div
                      style={{
                        width: '16px',
                        height: '16px',
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        backgroundColor: getCategoryColor(selectedElement.category),
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text variant="body">
                      {(selectedElement.category || 'Unknown')
                        .replace(/-/g, ' ')
                        .replace(/\b\w/g, l => l.toUpperCase())}
                    </Text>
                  </div>
                </div>
              </div>
            </Stack>
          </Card>
        )}
      </Stack>

      <style>{`
        @keyframes slideInUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </Container>
  );
}

import { useState, useEffect, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Text, Input, Button, Badge } from '@ggui-ai/design/primitives';

interface Props {
  title?: string;
  currentUser?: string;
  participantCount?: number;
  messages?: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSend?: (payload: { text: string; timestamp: string }) => void;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

const formatTime = (isoString?: string): string => {
  if (!isoString) return '';
  try {
    const date = new Date(isoString);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
};

interface MessageGroup {
  sender: string;
  items: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

const groupMessages = (messages: Array<{ sender?: string; text?: string; timestamp?: string }>): MessageGroup[] => {
  if (!messages.length) return [];
  const groups: MessageGroup[] = [];
  let currentGroup: MessageGroup | null = null;
  messages.forEach((msg) => {
    const sender = msg.sender || 'Unknown';
    if (!currentGroup || currentGroup.sender !== sender) {
      currentGroup = { sender, items: [] };
      groups.push(currentGroup);
    }
    currentGroup.items.push(msg);
  });
  return groups;
};

export default function ChatInterface({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  onSend,
  onSendMessage,
}: Props) {
  const [messageText, setMessageText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const groupedMessages = useMemo(() => groupMessages(messages), [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = () => {
    const trimmedText = messageText.trim();
    if (!trimmedText) return;
    const timestamp = new Date().toISOString();
    const payload = { text: trimmedText, timestamp };
    onSend?.(payload);
    onSendMessage?.(payload);
    setMessageText('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Container maxWidth="md" padding={0}>
      <Card padding={0} shadow="md" border={true}>
        <Box style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) 0 0' }}>
          <Row gap={16} align="center" justify="between">
            <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{title}</Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm" pill={true}>
                {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
              </Badge>
            )}
          </Row>
        </Box>

        <Box style={{ background: 'var(--ggui-color-surface, #fafafa)', padding: 'var(--ggui-spacing-4, 16px)', minHeight: '400px', maxHeight: '500px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}>
          {groupedMessages.length === 0 ? (
            <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '300px' }}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            groupedMessages.map((group, groupIdx) => {
              const isOwnGroup = group.sender === currentUser;
              return (
                <Stack key={`group-${groupIdx}`} direction="vertical" gap={8} align={isOwnGroup ? 'end' : 'start'}>
                  {!isOwnGroup && (
                    <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {group.sender}
                    </Text>
                  )}
                  {group.items.map((item, itemIdx) => {
                    const bgColor = isOwnGroup ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)';
                    const textColor = isOwnGroup ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)';
                    return (
                      <Box key={`msg-${groupIdx}-${itemIdx}`} style={{ background: bgColor, padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', maxWidth: '70%', wordWrap: 'break-word', overflowWrap: 'break-word' }}>
                        <Text variant="body" color={textColor}>{item.text || ''}</Text>
                        {item.timestamp && (
                          <time dateTime={item.timestamp}>
                            <Text variant="caption" color={textColor} align={isOwnGroup ? 'right' : 'left'} style={{ opacity: 0.75, display: 'block' }}>
                              {formatTime(item.timestamp)}
                            </Text>
                          </time>
                        )}
                      </Box>
                    );
                  })}
                </Stack>
              );
            })
          )}
          <div ref={messagesEndRef} style={{ height: 0 }} />
        </Box>

        <Box style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', background: 'var(--ggui-color-surface, #fafafa)', borderRadius: '0 0 var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)' }}>
          <Row gap={8} align="center">
            <Input label="Message" placeholder="Type a message..." value={messageText} onChange={setMessageText} onKeyDown={handleKeyDown} style={{ flex: 1 }} />
            <Button variant="primary" size="sm" disabled={messageText.trim() === ''} onClick={handleSend} aria-label="Send message">
              Send
            </Button>
          </Row>
        </Box>
      </Card>
    </Container>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Box,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {
  const [displayStocks, setDisplayStocks] = useState(stocks);
  const [connectionStatus, setConnectionStatus] = useState<
    'connected' | 'connecting' | 'disconnected'
  >('disconnected');
  const { motionEnabled } = useMotion();

  // Format timestamp for display
  const formatTimestamp = (isoString?: string): string => {
    if (!isoString) return 'Never';
    try {
      const date = new Date(isoString);
      return new Intl.DateTimeFormat('en-US', {
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true,
      }).format(date);
    } catch {
      return 'Invalid';
    }
  };

  // Listen for live data updates via ggui:agent-data stream
  useEffect(() => {
    if (typeof window === 'undefined') return;

    setConnectionStatus('connecting');

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.stocks && Array.isArray(customEvent.detail.stocks)) {
        setDisplayStocks(customEvent.detail.stocks);
        setConnectionStatus('connected');
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  // Update display stocks from props if no stream data yet
  useEffect(() => {
    if (stocks && stocks.length > 0 && connectionStatus === 'disconnected') {
      setDisplayStocks(stocks);
    }
  }, [stocks, connectionStatus]);

  return (
    <Container maxWidth="full" padding={24}>
      <MotionKeyframes />

      <Stack direction="vertical" gap={24}>
        {/* Header Section */}
        <Box
          style={{
            borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`,
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <Row justify="between" align="center">
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Text>

            {/* Connection Status Indicator */}
            <Stack direction="horizontal" gap={8} align="center">
              {connectionStatus === 'connecting' && (
                <>
                  <div
                    style={{
                      width: 8,
                      height: 8,
                      borderRadius: '50%',
                      backgroundColor: 'var(--ggui-color-warning-500, #f59e0b)',
                      animation: motionEnabled
                        ? 'pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite'
                        : 'none',
                    }}
                  />
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Connecting...
                  </Text>
                </>
              )}

              {connectionStatus === 'connected' && (
                <>
                  <div
                    style={{
                      width: 8,
                      height: 8,
                      borderRadius: '50%',
                      backgroundColor: 'var(--ggui-color-success-600, #16a34a)',
                    }}
                  />
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Live
                  </Text>
                </>
              )}

              {connectionStatus === 'disconnected' && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-error-600, #dc2626)"
                >
                  Offline
                </Text>
              )}
            </Stack>
          </Row>

          {/* Last Updated Timestamp */}
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
          >
            Last Updated: {formatTimestamp(lastUpdated)}
          </Text>

          {/* Live Data Status */}
          <div
            aria-live="polite"
            aria-atomic="true"
            style={{ display: 'none' }}
          >
            {connectionStatus === 'connecting' && 'Connecting to live data...'}
            {connectionStatus === 'connected' && 'Market data is live'}
            {connectionStatus === 'disconnected' && 'Market data is offline'}
          </div>
        </Box>

        {/* Stock Cards Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
          role="grid"
          aria-label="Stock prices"
        >
          {displayStocks && displayStocks.length > 0 ? (
            displayStocks.map((stock, index) => {
              const symbol = stock.symbol || 'N/A';
              const name = stock.name || 'Unknown Company';
              const price = stock.price ?? 0;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;

              const isPositive = change >= 0;
              const arrowIcon = isPositive ? '▲' : '▼';
              const changeColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';

              return (
                <Card
                  key={`${symbol}-${index}`}
                  padding={16}
                  shadow="sm"
                  border={true}
                  style={{
                    borderColor: changeColor,
                    borderWidth: '2px',
                    animation: motionEnabled
                      ? `${animation.slideInUp}`
                      : 'none',
                    animationDelay: motionEnabled
                      ? `${index * 50}ms`
                      : '0ms',
                    transition: 'border-color 200ms ease-out',
                  }}
                  role="row"
                >
                  <Stack direction="vertical" gap={12}>
                    {/* Ticker Symbol */}
                    <Row justify="start" align="center">
                      <Text
                        variant="h2"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                        role="cell"
                      >
                        {symbol}
                      </Text>
                    </Row>

                    {/* Company Name */}
                    <Text
                      variant="body"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      role="cell"
                      style={{
                        fontSize: 'var(--ggui-font-size-sm, 14px)',
                      }}
                    >
                      {name}
                    </Text>

                    {/* Current Price */}
                    <Text
                      variant="h3"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      role="cell"
                    >
                      ${price.toFixed(2)}
                    </Text>

                    {/* Change Amount, Percent, and Arrow Icon */}
                    <Row gap={8} align="center">
                      <Text
                        variant="body"
                        weight="semibold"
                        color={changeColor}
                        role="cell"
                        style={{
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        {isPositive ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>

                      <Text
                        variant="body"
                        weight="semibold"
                        color={changeColor}
                        role="cell"
                        style={{
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        ({isPositive ? '+' : ''}
                        {changePercent.toFixed(2)}%)
                      </Text>

                      <Text
                        variant="body"
                        weight="bold"
                        color={changeColor}
                        role="cell"
                        style={{
                          fontSize: 'var(--ggui-font-size-base, 16px)',
                          lineHeight: 1,
                        }}
                        aria-label={isPositive ? 'Price increased' : 'Price decreased'}
                      >
                        {arrowIcon}
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Box
              style={{
                gridColumn: '1 / -1',
                padding: 'var(--ggui-spacing-6, 24px)',
                textAlign: 'center',
              }}
            >
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                No stock data available. {connectionStatus === 'connecting' ? 'Loading...' : ''}
              </Text>
            </Box>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Select, Checkbox, RadioGroup, Button, Divider, Box, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback when onboarding is complete */
  onComplete?: (profileData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
}

function ProfileSetup({ formData, errors, touched, avatarOptions, onUpdateField, motionEnabled }: any) {
  return (
    <Stack direction="vertical" gap={16} style={{ animation: motionEnabled ? animation.slideInUp : 'none' }}>
      <Input label="Full Name" placeholder="John Doe" value={formData.name} onChange={(v) => onUpdateField('name', v)} error={touched.name ? errors.name : undefined} required />
      <Input label="Email Address" type="email" placeholder="you@example.com" value={formData.email} onChange={(v) => onUpdateField('email', v)} error={touched.email ? errors.email : undefined} required />
      <Stack direction="vertical" gap={8}>
        <Text variant="label" weight="medium">Choose Your Avatar</Text>
        <Row gap={12} wrap={true}>
          {avatarOptions.map((avatar: string, idx: number) => (
            <Button key={idx} variant={formData.avatar === avatar ? 'primary' : 'outline'} size="lg" onClick={() => onUpdateField('avatar', avatar)} style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', display: 'flex', alignItems: 'center', justifyContent: 'center', minWidth: '60px', height: '60px', padding: 'var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', transition: 'all 0.2s ease-out' }}>
              {avatar}
            </Button>
          ))}
        </Row>
        {touched.avatar && errors.avatar && <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">{errors.avatar}</Text>}
      </Stack>
    </Stack>
  );
}

function PreferencesStep({ formData, errors, touched, roleOptions, onUpdateField, motionEnabled }: any) {
  return (
    <Stack direction="vertical" gap={16} style={{ animation: motionEnabled ? animation.slideInUp : 'none' }}>
      <Select label="Your Role" placeholder="Select a role" value={formData.role} onChange={(v) => onUpdateField('role', v)} options={roleOptions.map((r: string) => ({ value: r, label: r }))} error={touched.role ? errors.role : undefined} required />
      <Checkbox label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => onUpdateField('emailNotifications', v)} description="Receive updates about your account activity" />
      <RadioGroup label="Appearance" value={formData.theme} onChange={(v) => onUpdateField('theme', v)} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} direction="horizontal" />
    </Stack>
  );
}

function ReviewStep({ formData, motionEnabled }: any) {
  return (
    <Stack direction="vertical" gap={16} style={{ animation: motionEnabled ? animation.slideInUp : 'none' }}>
      <Card padding="var(--ggui-spacing-4, 16px)" border={true} shadow="none">
        <Stack direction="vertical" gap={12} align="center">
          <Box style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>{formData.avatar}</Box>
          <Row gap={8} justify="center" align="center"><Text weight="semibold">Name:</Text><Text>{formData.name}</Text></Row>
          <Row gap={8} justify="center" align="center"><Text weight="semibold">Email:</Text><Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text></Row>
        </Stack>
      </Card>
      <Divider margin={8} />
      <Card padding="var(--ggui-spacing-4, 16px)" border={true} shadow="none">
        <Stack direction="vertical" gap={12}>
          <Text variant="h3">Preferences</Text>
          <Row gap={8}><Text weight="semibold">Role:</Text><Text>{formData.role}</Text></Row>
          <Row gap={8}><Text weight="semibold">Notifications:</Text><Icon name={formData.emailNotifications ? 'check' : 'x'} size={16} color={formData.emailNotifications ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-neutral-500, #6b7280)'} /></Row>
          <Row gap={8}><Text weight="semibold">Theme:</Text><Text>{formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}</Text></Row>
        </Stack>
      </Card>
    </Stack>
  );
}

function StepIndicator({ step, steps }: any) {
  return (
    <Row gap={8} justify="center" align="center" wrap={true}>
      {steps.map((stepName: string, idx: number) => (
        <Stack key={stepName} direction="vertical" align="center" gap={4}>
          <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: '32px', height: '32px', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', backgroundColor: idx < step ? 'var(--ggui-color-primary-600, #0284c7)' : idx === step ? 'var(--ggui-color-primary-500, #0ea5e9)' : 'var(--ggui-color-neutral-200, #e5e7eb)', color: idx <= step ? 'white' : 'var(--ggui-color-neutral-600, #4b5563)', fontWeight: 'var(--ggui-font-weight-bold, 700)', fontSize: 'var(--ggui-font-size-sm, 14px)', transition: 'all 0.2s ease-out' }} aria-label={`Step ${idx + 1}`} aria-current={idx === step ? 'step' : undefined}>
            {idx < step ? <Icon name="check" size={16} /> : idx + 1}
          </Box>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stepName}</Text>
        </Stack>
      ))}
    </Row>
  );
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState<FormData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0] ?? '👤',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? false,
    theme: initialProfile?.theme ?? 'light',
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];
  const stepTitles = ['Set Up Your Profile', 'Your Preferences', 'Review & Confirm'];
  const stepDescriptions = ['Tell us about yourself', 'Customize your experience', 'Please verify your information'];

  const validateEmail = (email: string): string => (!email ? 'Email is required' : !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? 'Invalid email format' : '');
  const validateName = (name: string): string => (!name || !name.trim() ? 'Name is required' : '');
  const validateRole = (role: string): string => (!role ? 'Please select a role' : '');

  const updateField = (field: keyof FormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setTouched((prev) => ({ ...prev, [field]: true }));
    let error = '';
    if (field === 'email' && value) error = validateEmail(value);
    else if (field === 'name' && value) error = validateName(value);
    else if (field === 'role' && value) error = validateRole(value);
    setErrors((prev) => ({ ...prev, [field]: error }));
  };

  const validateStep = (stepNum: number): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;
    if (stepNum === 0) {
      if (!formData.name.trim()) { newErrors.name = 'Name is required'; isValid = false; }
      const emailError = validateEmail(formData.email);
      if (emailError) { newErrors.email = emailError; isValid = false; }
      if (!formData.avatar) { newErrors.avatar = 'Please select an avatar'; isValid = false; }
    } else if (stepNum === 1) {
      const roleError = validateRole(formData.role);
      if (roleError) { newErrors.role = roleError; isValid = false; }
    }
    if (!isValid) setErrors(newErrors);
    return isValid;
  };

  const handleNext = () => { if (validateStep(step)) setStep((s) => s + 1); };
  const handleBack = () => { setStep((s) => Math.max(0, s - 1)); };
  const handleComplete = async () => { if (onComplete) { setIsSubmitting(true); try { await onComplete(formData); } finally { setIsSubmitting(false); } } };

  const renderStepContent = () => {
    switch (step) {
      case 0: return <ProfileSetup formData={formData} errors={errors} touched={touched} avatarOptions={avatarOptions} onUpdateField={updateField} motionEnabled={motionEnabled} />;
      case 1: return <PreferencesStep formData={formData} errors={errors} touched={touched} roleOptions={roleOptions} onUpdateField={updateField} motionEnabled={motionEnabled} />;
      case 2: return <ReviewStep formData={formData} motionEnabled={motionEnabled} />;
      default: return null;
    }
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="sm" border={true}>
          <Stack direction="vertical" gap={24}>
            <Stack direction="vertical" gap={8} align="center">
              <Text variant="h2" align="center">{stepTitles[step]}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">{stepDescriptions[step]}</Text>
            </Stack>
            <StepIndicator step={step} steps={steps} />
            <Divider margin={16} />
            {renderStepContent()}
            <Divider margin={16} />
            <Row gap={12} justify="between" align="center">
              {step === 2 ? <Button variant="outline" onClick={handleBack} disabled={isSubmitting}>Go Back</Button> : <div />}
              {step < 2 ? <Button variant="primary" onClick={handleNext} disabled={isSubmitting}>Next</Button> : <Button variant="primary" onClick={handleComplete} loading={isSubmitting} disabled={isSubmitting}>{isSubmitting ? 'Completing...' : 'Complete Setup'}</Button>}
            </Row>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

