interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 58,
  windSpeed = 14,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 16 },
    { day: 'Tue', icon: '⛅', high: 21, low: 15 },
    { day: 'Wed', icon: '🌧️', high: 19, low: 13 },
    { day: 'Thu', icon: '🌤️', high: 23, low: 14 },
    { day: 'Fri', icon: '☁️', high: 20, low: 12 },
  ],
}: Props) {
  const normalizedUnit = unit ?? 'C';
  const formattedTemp = `${temperature}°${normalizedUnit}`;
  const windUnit = normalizedUnit === 'F' ? 'mph' : 'km/h';

  return (
    <Container maxWidth="sm" padding={16} center>
      <Card
        padding={24}
        shadow="md"
        border
