import { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Row,
  Box,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (data: { title: string; priority: 'low' | 'medium' | 'high'; column: string }) => Promise<void> | void;
}

type TaskItem = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

const normalizeTask = (task: Props['tasks'][number], index: number, fallbackColumn: string): TaskItem => ({
  id: task.id || `task-${index + 1}`,
  title: task.title || 'Untitled Task',
  priority: task.priority || 'medium',
  assignee: task.assignee || 'NA',
  column: task.column || fallbackColumn,
  dueDate: task.dueDate || '',
});

export default function GeneratedComponent(props: Props) {
  const defaultColumn = props.columns?.[0]?.id || 'todo';
  const [taskState, setTaskState] = useState<TaskItem[]>(
    (props.tasks || []).map((t, i) => normalizeTask(t, i, defaultColumn))
  );

  const [showAddFormByColumn, setShowAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTitleByColumn, setNewTitleByColumn] = useState<Record<string, string>>({});
  const [newPriorityByColumn, setNewPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [newErrorByColumn, setNewErrorByColumn] = useState<Record<string, string>>({});
  const [submitStateByColumn, setSubmitStateByColumn] = useState<Record<string, 'idle' | 'submitting' | 'success' | 'error'>>({});

  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [editingError, setEditingError] = useState<string>('');

  const totalTasks = taskState.length;
  const doneColumnId = (props.columns.find((c) => (c.name || '').toLowerCase() === 'done')?.id || 'done');
  const completedCount = taskState.filter((t) => t.column === doneColumnId).length;

  const priorityVariant = (priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' => {
    if (priority === 'low') return 'success';
    if (priority === 'medium') return 'warning';
    return 'error';
  };

  const columnOptions = useMemo(
    () => (props.columns || []).map((c) => ({ value: c.id || '', label: c.name || 'Column' })),
    [props.columns]
  );

  const moveTask = (taskId: string, nextColumn: string) => {
    setTaskState((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: nextColumn } : t))
    );
    props.taskUpdate?.({ action: 'move', taskId, data: { column: nextColumn } });
  };

  const startEdit = (task: TaskItem) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
    setEditingError('');
  };

  const saveEdit = (taskId: string) => {
    if (!editingTitle.trim()) {
      setEditingError('Task title is required');
      return;
    }
    setTaskState((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle.trim() } : t))
    );
    props.taskUpdate?.({ action: 'edit', taskId, data: { title: editingTitle.trim() } });
    setEditingTaskId('');
    setEditingTitle('');
    setEditingError('');
  };

  const addTask = async (columnId: string) => {
    const title = (newTitleByColumn[columnId] || '').trim();
    const priority = newPriorityByColumn[columnId] || 'medium';
    if (!title) {
      setNewErrorByColumn((prev) => ({ ...prev, [columnId]: 'Title is required' }));
      return;
    }

    setNewErrorByColumn((prev) => ({ ...prev, [columnId]: '' }));
    setSubmitStateByColumn((prev) => ({ ...prev, [columnId]: 'submitting' }));

    try {
      await props.onSubmit?.({ title, priority, column: defaultColumn });

      const newTask: TaskItem = {
        id: `task-${Date.now()}`,
        title,
        priority,
        assignee: 'NA',
        column: defaultColumn,
        dueDate: '',
      };

      setTaskState((prev) => [...prev, newTask]);
      props.taskUpdate?.({
        action: 'create',
        taskId: newTask.id,
        data: { title: newTask.title, priority: newTask.priority, column: newTask.column },
      });

      setSubmitStateByColumn((prev) => ({ ...prev, [columnId]: 'success' }));
      setNewTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: 'medium' }));
      setTimeout(() => {
        setSubmitStateByColumn((prev) => ({ ...prev, [columnId]: 'idle' }));
        setShowAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
      }, 800);
    } catch {
      setSubmitStateByColumn((prev) => ({ ...prev, [columnId]: 'error' }));
    }
  };

  return (
    <Stack gap={16}>
      <Card border shadow="sm" padding={16}>
        <Row justify="between" align="center">
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Task Board</Text>
          <Row gap={12} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Total: {totalTasks}
            </Text>
            <Text variant="label" color="var(--ggui-color-success-600, #16a34a)">
              Completed: {completedCount}
            </Text>
          </Row>
        </Row>
      </Card>

      <Row gap={16} align="start">
        {(props.columns || []).map((column) => {
          const columnId = column.id || '';
          const columnName = column.name || 'Column';
          const tasksInColumn = taskState.filter((t) => t.column === columnId);
          const addOpen = !!showAddFormByColumn[columnId];
          const submitState = submitStateByColumn[columnId] || 'idle';

          return (
            <Card key={columnId} border shadow="sm" padding={12}>
              <Stack gap={12}>
                <Row justify="between" align="center">
                  <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">
                    {columnName}
                  </Text>
                  <Badge variant="secondary" size="sm">{tasksInColumn.length}</Badge>
                </Row>

                <Stack gap={10}>
                  {tasksInColumn.map((task) => (
                    <Card key={task.id} border shadow="none" padding={10}>
                      <Stack gap={8}>
                        {editingTaskId === task.id ? (
                          <Stack gap={8}>
                            <Input
                              label="Task title"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              error={editingError}
                              required
                            />
                            <Row gap={8}>
                              <Button size="sm" variant="primary" onClick={() => saveEdit(task.id)}>
                                Save
                              </Button>
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => {
                                  setEditingTaskId('');
                                  setEditingError('');
                                }}
                              >
                                Cancel
                              </Button>
                            </Row>
                          </Stack>
                        ) : (
                          <Row justify="between" align="center">
                            <Text
                              variant="body"
                              weight="medium"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {task.title}
                            </Text>
                            <Button
                              size="xs"
                              variant="ghost"
                              onClick={() => startEdit(task)}
                              leftIcon={<Icon name="settings" size={14} />}
                            >
                              Edit
                            </Button>
                          </Row>
                        )}

                        <Row justify="between" align="center">
                          <Badge variant={priorityVariant(task.priority)} size="sm">
                            {task.priority}
                          </Badge>
                          <Box
                            padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
                            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                            borderRadius="var(--ggui-shape-radius-full, 9999px)"
                          >
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {task.assignee}
                            </Text>
                          </Box>
                        </Row>

                        {task.dueDate ? (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Due: {task.dueDate}
                          </Text>
                        ) : null}

                        <Select
                          label="Move task"
                          value={task.column}
                          onChange={(value) => moveTask(task.id, value)}
                          options={columnOptions}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addOpen ? (
                  <Card border shadow="none" padding={10}>
                    <Stack gap={8}>
                      <Input
                        label="Task title"
                        value={newTitleByColumn[columnId] || ''}
                        onChange={(value) =>
                          setNewTitleByColumn((prev) => ({ ...prev, [columnId]: value }))
                        }
                        error={newErrorByColumn[columnId] || ''}
                        placeholder="Enter task title"
                        required
                      />
                      <Select
                        label="Priority"
                        value={newPriorityByColumn[columnId] || 'medium'}
                        onChange={(value) =>
                          setNewPriorityByColumn((prev) => ({
                            ...prev,
                            [columnId]: (value as 'low' | 'medium' | 'high') || 'medium',
                          }))
                        }
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Row gap={8}>
                        <Button
                          variant="primary"
                          size="sm"
                          onClick={() => addTask(columnId)}
                          disabled={submitState === 'submitting'}
                          loading={submitState === 'submitting'}
                        >
                          Submit
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => setShowAddFormByColumn((prev) => ({ ...prev, [columnId]: false }))}
                          disabled={submitState === 'submitting'}
                        >
                          Cancel
                        </Button>
                      </Row>
                      {submitState === 'success' ? (
                        <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                          Task created successfully
                        </Text>
                      ) : null}
                      {submitState === 'error' ? (
                        <Text variant="caption" color="var(--ggui-color-error-600, #dc2626)">
                          Failed to create task
                        </Text>
                      ) : null}
                    </Stack>
                  </Card>
                ) : null}

                <Button
                  variant="outline"
                  size="sm"
                  fullWidth
                  leftIcon={<Icon name="plus" size={14} />}
                  onClick={() => setShowAddFormByColumn((prev) => ({ ...prev, [columnId]: true }))}
                >
                  Add Task
                </Button>
              </Stack>
            </Card>
          );
        })}
      </Row>
    </Stack>
  );
}

import { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-info-500, #06b6d4)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  lanthanide: 'var(--ggui-color-success-600, #16a34a)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

const getCategoryColor = (category?: string) => {
  if (!category) return categoryColorMap.unknown;
  return categoryColorMap[category.toLowerCase()] ?? categoryColorMap.unknown;
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add(el.category || 'Unknown'));
    return Array.from(set);
  }, [elements]);

  return (
    <Card
      padding={16}
      border
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text variant="h2">Periodic Table</Text>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol"
          value={query}
          onChange={setQuery}
          helperText="Type to filter the table"
        />

        <div
          role="grid"
          aria-label="Periodic table of elements"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            padding: 'var(--ggui-spacing-2, 8px)',
            overflowX: 'auto',
          }}
        >
          {filteredElements.map((el) => {
            const row = el.row ?? 1;
            const col = el.col ?? 1;
            const symbol = el.symbol ?? '?';
            const atomicNumber = el.atomicNumber ?? 0;
            const isSelected = selectedAtomicNumber === atomicNumber;

            return (
              <Button
                key={`${atomicNumber}-${symbol}-${row}-${col}`}
                variant="ghost"
                size="sm"
                onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                style={{
                  gridRow: row,
                  gridColumn: col,
                  minHeight: 56,
                  position: 'relative',
                  border: `1px solid ${
                    isSelected
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-outline, #d4d4d8)'
                  }`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  background: getCategoryColor(el.category),
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  padding: 'var(--ggui-spacing-1, 4px)',
                }}
                aria-label={`${el.name ?? 'Unknown'} (${symbol}), atomic number ${atomicNumber}`}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: 2,
                    left: 4,
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    lineHeight: 1,
                  }}
                >
                  {atomicNumber}
                </span>
                <span
                  style={{
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    lineHeight: 1,
                  }}
                >
                  {symbol}
                </span>
              </Button>
            );
          })}
        </div>

        <Card
          padding={12}
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={6}>
            <Text variant="h3">Element Details</Text>
            {selectedElement ? (
              <>
                <Text><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
                <Text><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
                <Text><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
                <Text><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
                <Text><strong>Category:</strong> {selectedElement.category ?? '—'}</Text>
              </>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surface, #fafafa)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="h3">Legend</Text>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {categories.map((category) => (
                <div
                  key={category}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <span
                    aria-hidden
                    style={{
                      width: 14,
                      height: 14,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      flexShrink: 0,
                    }}
                  />
                  <Text variant="caption">{category}</Text>
                </div>
              ))}
            </div>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Divider,
  Input,
  MotionKeyframes,
  Row,
  Stack,
  Text,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [messageBuffer, setMessageBuffer] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >(messages);
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const inputWrapRef = useRef<HTMLDivElement | null>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    setMessageBuffer(messages);
  }, [messages]);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messageBuffer]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{
        sender?: string;
        text?: string;
        timestamp?: string;
      }>;
      const detail = customEvent.detail || {};
      const incoming = {
        sender: detail.sender ?? '',
        text: detail.text ?? '',
        timestamp: detail.timestamp ?? new Date().toISOString(),
      };
      setMessageBuffer((prev) => [...prev, incoming]);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const computedParticipantCount = useMemo(() => {
    if (typeof participantCount === 'number') return participantCount;
    const unique = new Set(
      messageBuffer
        .map((m) => (m.sender || '').trim())
        .filter((sender) => sender.length > 0),
    );
    return unique.size;
  }, [participantCount, messageBuffer]);

  const formatTimestamp = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return timestamp;
    return `${date.toLocaleDateString()} ${date.toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit',
    })}`;
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
    if (inputWrapRef.current) {
      const inputEl = inputWrapRef.current.querySelector('input');
      inputEl?.focus();
    }
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={0}
        shadow="sm"
        border
      >
        <Box
          role="region"
          aria-label={title}
          style={{
            display: 'flex',
            flexDirection: 'column',
            height: '520px',
            background: 'var(--ggui-color-surface, #fafafa)',
            color: 'var(--ggui-color-onSurface, #18181b)',
          }}
        >
          <Box
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Row justify="between" align="center">
              <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {title}
              </Text>
              <Badge variant="secondary" size="sm" pill>
                {`${computedParticipantCount} participants`}
              </Badge>
            </Row>
          </Box>

          <Divider margin={0} />

          <Box
            ref={scrollRef}
            role="log"
            aria-live="polite"
            aria-relevant="additions text"
            aria-atomic="false"
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <Stack gap={4}>
              {messageBuffer.map((msg, index) => {
                const prev = messageBuffer[index - 1];
                const isNewGroup = !prev || prev.sender !== msg.sender;
                const isOwn = (msg.sender || '') === currentUser;
                const sender = msg.sender || 'Unknown';
                const text = msg.text || '';
                const formatted = formatTimestamp(msg.timestamp);

                return (
                  <Box key={`${msg.sender || 'unknown'}-${msg.timestamp || index}-${index}`}>
                    <Row justify={isOwn ? 'end' : 'start'}>
                      <Box
                        style={{
                          width: '100%',
                          maxWidth: '75%',
                          marginTop: isNewGroup ? 'var(--ggui-spacing-2, 8px)' : '4px',
                          animation: motionEnabled ? animation.slideInUp : 'none',
                        }}
                      >
                        {isNewGroup && (
                          <Text
                            variant="label"
                            weight="medium"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                            align={isOwn ? 'right' : 'left'}
                          >
                            {sender}
                          </Text>
                        )}
                        <Box
                          style={{
                            marginTop: isNewGroup ? '4px' : '2px',
                            padding:
                              'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                            background: isOwn
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            color: isOwn
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurface, #18181b)',
                            border: `1px solid var(--ggui-color-outlineVariant, #e4e4e7)`,
                          }}
                        >
                          <Text
                            variant="body"
                            color={
                              isOwn
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {text}
                          </Text>
                          {formatted ? (
                            <Text
                              variant="caption"
                              color={
                                isOwn
                                  ? 'var(--ggui-color-surface, #fafafa)'
                                  : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                              }
                            >
                              {formatted}
                            </Text>
                          ) : null}
                        </Box>
                      </Box>
                    </Row>
                  </Box>
                );
              })}
            </Stack>
          </Box>

          <Divider margin={0} />

          <Box style={{ padding: 'var(--ggui-spacing-4, 16px)' }}>
            <Row gap={8} align="end">
              <Box ref={inputWrapRef} style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message"
                  value={draft}
                  onChange={setDraft}
                  onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </Box>
              <Box
                style={{
                  outline: '2px solid transparent',
                  outlineOffset: '2px',
                }}
              >
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleSend}
                  disabled={draft.trim().length === 0}
                  aria-label="Send message"
                >
                  Send
                </Button>
              </Box>
            </Row>
          </Box>
        </Box>
      </Card>
    </>
  );
}

export const __GGUI_META__ = {
  category: 'communication',
  description:
    'Real-time chat interface with grouped messages, stream event ingestion, auto-scroll log, and send composer wired to action callback.',
};

