import { useEffect, useState } from 'react';
import {
  Container,
  Stack,
  Row,
  Card,
  Box,
  Text,
  Heading,
  Badge,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const { motionEnabled } = useMotion();
  const [displayedStocks, setDisplayedStocks] = useState<Props['stocks']>(stocks);
  const [displayedLastUpdated, setDisplayedLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'live' | 'disconnected'>('connecting');
  const [isInitialLoading, setIsInitialLoading] = useState(true);

  useEffect(() => {
    setDisplayedStocks(stocks);
    setDisplayedLastUpdated(lastUpdated);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const detail = customEvent?.detail;

      if (!detail || typeof detail !== 'object') return;

      let hasValidUpdate = false;

      if (Array.isArray(detail.stocks)) {
        setDisplayedStocks(detail.stocks as Props['stocks']);
        hasValidUpdate = true;
      }

      if (typeof detail.lastUpdated === 'string') {
        setDisplayedLastUpdated(detail.lastUpdated);
        hasValidUpdate = true;
      }

      if (hasValidUpdate) {
        setConnectionState('live');
        setIsInitialLoading(false);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setIsInitialLoading(false);
      setConnectionState((prev) => (prev === 'live' ? 'live' : 'disconnected'));
    }, 2500);

    return () => window.clearTimeout(timer);
  }, []);

  const formatFixed2 = (value?: number) => (typeof value === 'number' ? value : 0).toFixed(2);

  const formatSigned = (value?: number) => {
    const n = typeof value === 'number' ? value : 0;
    return `${n >= 0 ? '+' : '-'}${Math.abs(n).toFixed(2)}`;
  };

  const getChangeColor = (value?: number) => {
    const n = typeof value === 'number' ? value : 0;
    if (n > 0) return 'var(--ggui-color-success-500, #22c55e)';
    if (n < 0) return 'var(--ggui-color-error-500, #ef4444)';
    return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  };

  const getBadgeVariant = () => {
    if (connectionState === 'live') return 'success' as const;
    if (connectionState === 'connecting') return 'info' as const;
    return 'warning' as const;
  };

  const statusText =
    connectionState === 'live'
      ? 'Live'
      : connectionState === 'connecting'
      ? 'Connecting'
      : 'No stream';

  return (
    <section
      aria-label="Market Watch stock ticker"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-6, 24px)',
      }}
    >
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack gap={24}>
          <Row justify="between" align="center" wrap gap={8}>
            <Heading level={2}>Market Watch</Heading>
            <Stack gap={8} align="end">
              <div aria-live="polite" aria-atomic="true">
                <Row gap={8} align="center">
                  <Badge variant={getBadgeVariant()}>{statusText}</Badge>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Last Updated:{' '}
                    {displayedLastUpdated ? (
                      <time dateTime={displayedLastUpdated}>{displayedLastUpdated}</time>
                    ) : (
                      'Not available'
                    )}
                  </Text>
                </Row>
              </div>
            </Stack>
          </Row>

          {isInitialLoading && (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Connecting to live market feed…
            </Text>
          )}

          {!isInitialLoading && displayedStocks.length === 0 && (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stocks available.
            </Text>
          )}

          <Box>
            <style>
              {`
                .stock-grid {
                  display: grid;
                  gap: var(--ggui-spacing-4, 16px);
                  grid-template-columns: repeat(1, minmax(0, 1fr));
                }
                @media (min-width: 768px) {
                  .stock-grid {
                    grid-template-columns: repeat(3, minmax(0, 1fr));
                  }
                }
              `}
            </style>
            <div className="stock-grid" role="list">
              {displayedStocks.map((stock, index) => {
                const symbol = stock.symbol || '—';
                const name = stock.name || 'Unknown company';
                const price = formatFixed2(stock.price);
                const changeAmount = formatSigned(stock.change);
                const changePercentNumber = typeof stock.changePercent === 'number' ? stock.changePercent : 0;
                const changePercent = formatSigned(changePercentNumber);
                const arrow = changePercentNumber < 0 ? '▼' : '▲';
                const changeColor = getChangeColor(changePercentNumber);

                return (
                  <Box
                    key={stock.symbol || index}
                    role="listitem"
                    style={{
                      border: `1px solid ${changeColor}`,
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      transition: transition.colors,
                      animation: motionEnabled ? animation.fadeIn : 'none',
                    }}
                  >
                    <Card
                      padding={16}
                      shadow="sm"
                      border
                      style={{
                        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      }}
                    >
                      <Stack gap={8}>
                        <Row justify="between" align="start">
                          <Stack gap={4}>
                            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                              {symbol}
                            </Text>
                            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {name}
                            </Text>
                          </Stack>
                        </Row>

                        <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          ${price}
                        </Text>

                        <Row align="center" gap={8}>
                          <Text variant="body" color={changeColor}>
                            {changeAmount}
                          </Text>
                          <Text variant="body" color={changeColor}>
                            {arrow} {changePercent}%
                          </Text>
                        </Row>
                      </Stack>
                    </Card>
                  </Box>
                );
              })}
            </div>
          </Box>
        </Stack>
      </Container>
    </section>
  );
}

import { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Heading,
  Text,
  Box,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  MotionKeyframes,
  useMotion,
  Icon,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Errors {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  theme?: string;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = [],
  roleOptions = [],
  onComplete,
}: Props) {
  const { motionEnabled } = useMotion();
  const [currentStep, setCurrentStep] = useState(0);
  const [submittedStepAttempt, setSubmittedStepAttempt] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errors, setErrors] = useState<Errors>({});
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    avatar: '',
    role: '',
    emailNotifications: false,
    theme: 'light',
  });

  useEffect(() => {
    setFormData({
      name: initialProfile.name ?? '',
      email: initialProfile.email ?? '',
      avatar:
        initialProfile.avatar && avatarOptions.includes(initialProfile.avatar)
          ? initialProfile.avatar
          : '',
      role:
        initialProfile.role && roleOptions.includes(initialProfile.role)
          ? initialProfile.role
          : '',
      emailNotifications: !!initialProfile.emailNotifications,
      theme:
        initialProfile.theme === 'light' || initialProfile.theme === 'dark'
          ? initialProfile.theme
          : 'light',
    });
  }, [initialProfile, avatarOptions, roleOptions]);

  const roleSelectOptions = useMemo(
    () => roleOptions.map((role) => ({ value: role, label: role })),
    [roleOptions]
  );

  const emailRegex = /^[^@\s]+@[^@\s]+\.[^@\s]+$/;

  const validateStep = (step: number, data: FormData): Errors => {
    const nextErrors: Errors = {};
    if (step === 0) {
      if (!data.name.trim()) nextErrors.name = 'Name is required';
      if (!data.email.trim()) nextErrors.email = 'Email is required';
      else if (!emailRegex.test(data.email)) nextErrors.email = 'Invalid email format';
      if (!data.avatar) nextErrors.avatar = 'Please select an avatar';
      else if (!avatarOptions.includes(data.avatar)) nextErrors.avatar = 'Invalid avatar selection';
    }
    if (step === 1) {
      if (!data.role) nextErrors.role = 'Role is required';
      else if (!roleOptions.includes(data.role)) nextErrors.role = 'Invalid role selection';
      if (!data.theme) nextErrors.theme = 'Theme is required';
      else if (!['light', 'dark'].includes(data.theme)) nextErrors.theme = 'Theme must be light or dark';
    }
    return nextErrors;
  };

  const validateAll = (data: FormData): Errors => ({
    ...validateStep(0, data),
    ...validateStep(1, data),
  });

  const stepErrors = validateStep(currentStep, formData);
  const isCurrentStepValid = Object.keys(stepErrors).length === 0;
  const progressPercent = ((currentStep + 1) / 3) * 100;

  const updateField = <K extends keyof FormData>(field: K, value: FormData[K]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      const newData = { ...formData, [field]: value };
      const newErrs = validateAll(newData);
      setErrors((prev) => ({ ...prev, [field]: newErrs[field] }));
    }
  };

  const handleNext = () => {
    setSubmittedStepAttempt(true);
    const nextErrors = validateStep(currentStep, formData);
    setErrors((prev) => ({ ...prev, ...nextErrors }));
    if (Object.keys(nextErrors).length === 0) {
      setCurrentStep((s) => Math.min(2, s + 1));
      setSubmittedStepAttempt(false);
    }
  };

  const handleBack = () => {
    setCurrentStep((s) => Math.max(0, s - 1));
    setSubmittedStepAttempt(false);
  };

  const handleComplete = async () => {
    setSubmittedStepAttempt(true);
    const allErrors = validateAll(formData);
    setErrors(allErrors);
    if (Object.keys(allErrors).length > 0) return;
    setIsSubmitting(true);
    try {
      onComplete?.(formData);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="md" center>
      <MotionKeyframes />
      <Card padding={24} shadow="md" border>
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Onboarding Setup</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep + 1} of 3
            </Text>

            <Row
              justify="between"
              align="center"
              gap={8}
              style={{ width: '100%' }}
              aria-label="Onboarding progress"
            >
              {['Profile', 'Preferences', 'Review'].map((label, index) => {
                const active = currentStep === index;
                const complete = currentStep > index;
                return (
                  <Stack key={label} align="center" gap={6}>
                    <Box
                      style={{
                        width: 32,
                        height: 32,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        background:
                          active || complete
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        color:
                          active || complete
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                        border: `1px solid ${
                          active || complete
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-outline, #d4d4d8)'
                        }`,
                      }}
                      aria-current={active ? 'step' : undefined}
                    >
                      {complete ? <Icon name="check" size={16} /> : index + 1}
                    </Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {label}
                    </Text>
                  </Stack>
                );
              })}
            </Row>

            <Box
              role="progressbar"
              aria-valuemin={1}
              aria-valuemax={3}
              aria-valuenow={currentStep + 1}
              style={{
                width: '100%',
                height: 8,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                overflow: 'hidden',
              }}
            >
              <Box
                style={{
                  width: `${progressPercent}%`,
                  height: '100%',
                  background: 'var(--ggui-color-primary-600, #0284c7)',
                  transition: motionEnabled ? 'width 200ms ease' : 'none',
                }}
              />
            </Box>
          </Stack>

          <Divider />

          <Box
            style={{
              animation: motionEnabled ? animation.slideInUp : 'none',
            }}
          >
            {currentStep === 0 && (
              <Stack gap={16}>
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  required
                  error={submittedStepAttempt ? errors.name : ''}
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  required
                  error={submittedStepAttempt ? errors.email : ''}
                />

                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  <Row gap={8} wrap role="radiogroup" aria-label="Avatar selection">
                    {avatarOptions.map((avatar, index) => {
                      const selected = formData.avatar === avatar;
                      return (
                        <Button
                          key={`${avatar}-${index}`}
                          variant={selected ? 'primary' : 'outline'}
                          onClick={() => updateField('avatar', avatar)}
                        >
                          <Box
                            role="radio"
                            aria-checked={selected}
                            style={{
                              minWidth: 20,
                              outline: 'none',
                            }}
                          >
                            {avatar}
                          </Box>
                        </Button>
                      );
                    })}
                  </Row>
                  {submittedStepAttempt && errors.avatar ? (
                    <Text variant="caption" color="var(--ggui-color-error-600, #dc2626)">
                      {errors.avatar}
                    </Text>
                  ) : null}
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack gap={16}>
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => updateField('role', v)}
                  options={roleSelectOptions}
                  placeholder="Select role"
                  required
                  error={submittedStepAttempt ? errors.role : ''}
                />
                <Checkbox
                  label="Email notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => updateField('emailNotifications', v)}
                  description="Receive onboarding and product updates by email."
                />
                <Select
                  label="Theme preference"
                  value={formData.theme}
                  onChange={(v) => updateField('theme', v)}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  required
                  error={submittedStepAttempt ? errors.theme : ''}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={16}>
                <Card border padding={16}>
                  <Stack gap={10}>
                    <Text variant="label">Review your setup</Text>
                    <Row justify="between"><Text variant="body">Name</Text><Text variant="body">{formData.name}</Text></Row>
                    <Row justify="between"><Text variant="body">Email</Text><Text variant="body">{formData.email}</Text></Row>
                    <Row justify="between"><Text variant="body">Avatar</Text><Text variant="body">{formData.avatar}</Text></Row>
                    <Row justify="between"><Text variant="body">Role</Text><Text variant="body">{formData.role}</Text></Row>
                    <Row justify="between"><Text variant="body">Email Notifications</Text><Text variant="body">{formData.emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="body">Theme</Text><Text variant="body">{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                  </Stack>
                </Card>
                <Row justify="between">
                  <Button variant="outline" onClick={() => setCurrentStep(1)}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete} loading={isSubmitting}>
                    Complete Setup
                  </Button>
                </Row>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between" wrap>
            <Button variant="outline" onClick={handleBack} disabled={currentStep === 0}>
              Back
            </Button>
            {currentStep < 2 ? (
              <Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete} loading={isSubmitting}>
                Complete Setup
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
      {/* __GGUI_META__ */}
      {/* {"category":"forms","description":"A reusable 3-step onboarding wizard with profile setup, preferences, validation, progress indicator, animated transitions, and final completion callback."} */}
    </Container>
  );
}

