import { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId?: string; data: Record<string, unknown> }) => void;
  onSubmit?: (data: { title: string; priority: 'low' | 'medium' | 'high'; column: string }) => Promise<unknown> | unknown;
}

type Task = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  column: string;
  dueDate?: string;
};

export default function GeneratedComponent({
  tasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  taskUpdate = () => undefined,
  onSubmit = async () => undefined,
}: Props) {
  const normalizedTasks = useMemo<Task[]>(
    () =>
      tasks.map((t, index) => ({
        id: t.id || `task-${index + 1}`,
        title: t.title || 'Untitled Task',
        priority: t.priority || 'low',
        assignee: t.assignee || '',
        column: t.column || (columns[0]?.id || 'todo'),
        dueDate: t.dueDate || '',
      })),
    [tasks, columns]
  );

  const [localTasks, setLocalTasks] = useState<Task[]>(normalizedTasks);
  const [addOpenByColumn, setAddOpenByColumn] = useState<Record<string, boolean>>({});
  const [newTaskByColumn, setNewTaskByColumn] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [formError, setFormError] = useState<string>('');
  const [formSuccess, setFormSuccess] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  const totalTasks = localTasks.length;
  const doneColumnId = columns.find((c) => (c.name || '').toLowerCase() === 'done')?.id || 'done';
  const completedCount = localTasks.filter((t) => t.column === doneColumnId).length;

  const priorityVariant = (priority: Task['priority']) => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  };

  const moveTask = (taskId: string, targetColumn: string) => {
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  };

  const startEdit = (task: Task) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  };

  const saveEdit = (taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
    setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: trimmed } : t)));
    taskUpdate({ action: 'edit', taskId, data: { title: trimmed } });
    setEditingTaskId('');
    setEditingTitle('');
  };

  const openAddForm = (columnId: string) => {
    setAddOpenByColumn((prev) => ({ ...prev, [columnId]: true }));
    setNewTaskByColumn((prev) => ({
      ...prev,
      [columnId]: prev[columnId] || { title: '', priority: 'low' },
    }));
    setFormError('');
    setFormSuccess('');
  };

  const handleCreateTask = async (columnId: string) => {
    const form = newTaskByColumn[columnId] || { title: '', priority: 'low' as const };
    const title = form.title.trim();

    if (!title) {
      setFormError('Task title is required.');
      setFormSuccess('');
      return;
    }

    setIsSubmitting(true);
    setFormError('');
    setFormSuccess('');
    try {
      await onSubmit({ title, priority: form.priority, column: columns[0]?.id || 'todo' });

      const newTask: Task = {
        id: `task-${Date.now()}`,
        title,
        priority: form.priority,
        assignee: '',
        column: columns[0]?.id || 'todo',
        dueDate: '',
      };

      setLocalTasks((prev) => [newTask, ...prev]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: newTask });
      setFormSuccess('Task created successfully.');
      setAddOpenByColumn((prev) => ({ ...prev, [columnId]: false }));
      setNewTaskByColumn((prev) => ({ ...prev, [columnId]: { title: '', priority: 'low' } }));
    } catch {
      setFormError('Could not create task. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Stack gap={16}>
      <Card border shadow="sm" padding={16}>
        <Row justify="between" align="center">
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Task Board</Text>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Total: {totalTasks} • Completed: {completedCount}
          </Text>
        </Row>
      </Card>

      <Row gap={16} align="start">
        {columns.map((column) => {
          const columnId = column.id || '';
          const columnTasks = localTasks.filter((t) => t.column === columnId);
          const formState = newTaskByColumn[columnId] || { title: '', priority: 'low' as const };

          return (
            <Card key={columnId} border shadow="sm" padding={12}>
              <Stack gap={12}>
                <Row justify="between" align="center">
                  <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">
                    {column.name || 'Column'}
                  </Text>
                  <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                </Row>

                <Stack gap={8}>
                  {columnTasks.map((task) => (
                    <Card key={task.id} border shadow="none" padding={12}>
                      <Stack gap={8}>
                        <Row justify="between" align="center">
                          {editingTaskId === task.id ? (
                            <Input
                              label="Edit task title"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              placeholder="Task title"
                              required
                            />
                          ) : (
                            <Text
                              variant="body"
                              weight="semibold"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {task.title}
                            </Text>
                          )}

                          <Badge variant={priorityVariant(task.priority)} size="sm">
                            {task.priority}
                          </Badge>
                        </Row>

                        <Row justify="between" align="center">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {task.assignee ? `Assignee: ${task.assignee}` : 'Unassigned'}
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                          </Text>
                        </Row>

                        <Row gap={8}>
                          {editingTaskId === task.id ? (
                            <Button size="sm" variant="primary" onClick={() => saveEdit(task.id)}>
                              Save
                            </Button>
                          ) : (
                            <Button size="sm" variant="outline" onClick={() => startEdit(task)}>
                              Edit
                            </Button>
                          )}

                          <Select
                            label="Move task"
                            value={task.column}
                            onChange={(value) => moveTask(task.id, value)}
                            options={columns.map((c) => ({
                              value: c.id || '',
                              label: c.name || 'Column',
                            }))}
                          />
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addOpenByColumn[columnId] ? (
                  <Card border shadow="none" padding={12}>
                    <Stack gap={8}>
                      <Input
                        label="Task title"
                        value={formState.title}
                        onChange={(value) =>
                          setNewTaskByColumn((prev) => ({
                            ...prev,
                            [columnId]: { ...formState, title: value },
                          }))
                        }
                        placeholder="Enter task title"
                        error={formError}
                        required
                      />
                      <Select
                        label="Priority"
                        value={formState.priority}
                        onChange={(value) =>
                          setNewTaskByColumn((prev) => ({
                            ...prev,
                            [columnId]: {
                              ...formState,
                              priority: (value as 'low' | 'medium' | 'high') || 'low',
                            },
                          }))
                        }
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      {formSuccess ? (
                        <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                          {formSuccess}
                        </Text>
                      ) : null}
                      <Row gap={8}>
                        <Button
                          variant="primary"
                          size="sm"
                          onClick={() => handleCreateTask(columnId)}
                          disabled={isSubmitting}
                          loading={isSubmitting}
                        >
                          Submit
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setAddOpenByColumn((prev) => ({ ...prev, [columnId]: false }))}
                          disabled={isSubmitting}
                        >
                          Cancel
                        </Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="secondary" size="sm" onClick={() => openAddForm(columnId)}>
                    Add Task
                  </Button>
                )}
              </Stack>
            </Card>
          );
        })}
      </Row>
    </Stack>
  );
}

import { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColorMap = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-primary-700, #0369a1)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-500, #6b7280)',
    }),
    []
  );

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const n = (el.name ?? '').toLowerCase();
      const s = (el.symbol ?? '').toLowerCase();
      return n.includes(q) || s.includes(q);
    });
  }, [elements, search]);

  const selectedElement =
    elements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add((el.category ?? 'unknown').toLowerCase()));
    return Array.from(set);
  }, [elements]);

  return (
    <Stack gap={16}>
      <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
        Periodic Table of Elements
      </Text>

      <Input
        label="Search elements"
        placeholder="Search by name or symbol"
        value={search}
        onChange={setSearch}
      />

      <Card border>
        <div
          role="grid"
          aria-label="Periodic table grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            padding: 'var(--ggui-spacing-2, 8px)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
          }}
        >
          {filteredElements.map((el) => {
            const categoryKey = (el.category ?? 'unknown').toLowerCase();
            const color =
              categoryColorMap[categoryKey] ?? 'var(--ggui-color-neutral-500, #6b7280)';
            return (
              <button
                key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'na'}`}
                type="button"
                role="gridcell"
                aria-label={`${el.name ?? 'Unknown'} (${el.symbol ?? '?'})`}
                onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                style={{
                  gridColumn: el.col ?? 'auto',
                  gridRow: el.row ?? 'auto',
                  minHeight: 56,
                  border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  position: 'relative',
                  cursor: 'pointer',
                  transition: 'all 200ms ease',
                  boxShadow:
                    selectedAtomicNumber === el.atomicNumber
                      ? `0 0 0 2px ${color}`
                      : 'none',
                }}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: 4,
                    left: 6,
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  }}
                >
                  {el.atomicNumber ?? '-'}
                </span>
                <span
                  style={{
                    display: 'block',
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    textAlign: 'center',
                    color,
                    lineHeight: '56px',
                  }}
                >
                  {el.symbol ?? '?'}
                </span>
              </button>
            );
          })}
        </div>
      </Card>

      <Card border>
        <Stack gap={8}>
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">
            Element Details
          </Text>
          {selectedElement ? (
            <Stack gap={4}>
              <Text><strong>Name:</strong> {selectedElement.name ?? 'Unknown'}</Text>
              <Text><strong>Symbol:</strong> {selectedElement.symbol ?? '?'}</Text>
              <Text><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '-'}</Text>
              <Text><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '-'}</Text>
              <Text><strong>Category:</strong> {selectedElement.category ?? 'unknown'}</Text>
            </Stack>
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Click an element in the table to view details.
            </Text>
          )}
        </Stack>
      </Card>

      <Card border>
        <Stack gap={8}>
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">
            Legend
          </Text>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(170px, 1fr))', gap: 8 }}>
            {categories.map((cat) => (
              <div
                key={cat}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8,
                  border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  background: 'var(--ggui-color-surface, #fafafa)',
                }}
              >
                <span
                  aria-hidden
                  style={{
                    width: 12,
                    height: 12,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: categoryColorMap[cat] ?? 'var(--ggui-color-neutral-500, #6b7280)',
                  }}
                />
                <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                  {cat}
                </Text>
              </div>
            ))}
          </div>
        </Stack>
      </Card>
    </Stack>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Divider,
  Input,
  Row,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount = undefined,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [inputText, setInputText] = useState<string>('');
  const [localMessages, setLocalMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >(messages);

  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  const scrollToBottom = () => {
    const el = scrollRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [localMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const detail = customEvent?.detail ?? {};
      const nextMessage = {
        sender: detail?.sender,
        text: detail?.text,
        timestamp: detail?.timestamp,
      };
      setLocalMessages((prev) => [...prev, nextMessage]);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      startIndex: number;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    localMessages.forEach((msg, index) => {
      const previous = localMessages[index - 1];
      if (!previous || previous.sender !== msg.sender) {
        groups.push({ sender: msg.sender, startIndex: index, items: [msg] });
      } else {
        groups[groups.length - 1].items.push(msg);
      }
    });

    return groups;
  }, [localMessages]);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;

    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage?.(payload);

    setLocalMessages((prev) => [
      ...prev,
      { sender: currentUser, text: payload.text, timestamp: payload.timestamp },
    ]);
    setInputText('');
  };

  const formatTimestamp = (ts?: string) => {
    if (!ts) return '';
    const date = new Date(ts);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString();
  };

  const canSend = inputText.trim().length > 0;

  return (
    <Card padding={0} shadow="sm" border>
      <Stack gap={0}>
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surface, #fafafa)"
        >
          <Row justify="between" align="center">
            <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {title}
            </Text>
            {participantCount !== undefined ? (
              <Badge variant="primary" size="sm">
                {participantCount}
              </Badge>
            ) : null}
          </Row>
        </Box>

        <Divider margin={0} />

        <Box
          style={{
            height: '520px',
            display: 'flex',
            flexDirection: 'column',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box
            ref={scrollRef}
            role="log"
            aria-live="polite"
            aria-relevant="additions text"
            padding="var(--ggui-spacing-4, 16px)"
            style={{
              flex: 1,
              overflowY: 'auto',
            }}
          >
            <Stack gap={8}>
              {groupedMessages.map((group) => {
                const isCurrentUser = group.sender === currentUser;
                return (
                  <Box
                    key={`${group.sender}-${group.startIndex}`}
                    style={{
                      display: 'flex',
                      justifyContent: isCurrentUser ? 'flex-end' : 'flex-start',
                    }}
                  >
                    <Stack gap={4} style={{ maxWidth: '80%', alignItems: isCurrentUser ? 'flex-end' : 'flex-start' }}>
                      <Text
                        variant="label"
                        weight="medium"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {group.sender ?? 'Unknown'}
                      </Text>

                      <Stack gap={6}>
                        {group.items.map((message, index) => (
                          <Box
                            key={`${group.startIndex + index}-${message.timestamp ?? 'no-ts'}`}
                            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                            style={{
                              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                              background: isCurrentUser
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                              border: `1px solid var(--ggui-color-outlineVariant, #e4e4e7)`,
                            }}
                          >
                            <Stack gap={4}>
                              <Text
                                variant="body"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-onPrimary, #ffffff)'
                                    : 'var(--ggui-color-onSurface, #18181b)'
                                }
                              >
                                {message.text ?? ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-onPrimary, #ffffff)'
                                    : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                }
                              >
                                {formatTimestamp(message.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    </Stack>
                  </Box>
                );
              })}
            </Stack>
          </Box>

          <Divider margin={0} />

          <Box padding="var(--ggui-spacing-4, 16px)">
            <Row gap={8} align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  value={inputText}
                  onChange={setInputText}
                  placeholder="Type a message"
                  label="Message"
                  aria-label="Type a message"
                  onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </Box>
              <Button
                variant="primary"
                size="md"
                onClick={handleSend}
                disabled={!canSend}
                aria-label="Send message"
              >
                Send
              </Button>
            </Row>
          </Box>
        </Box>
      </Stack>
    </Card>
  );
}

import { useEffect, useState } from 'react';
import {
  Container,
  MotionKeyframes,
  useMotion,
  Stack,
  Row,
  Text,
  Card,
  Box,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const { stocks = [], lastUpdated } = props;
  const { motionEnabled } = useMotion();

  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [connectionError, setConnectionError] = useState<string>('');

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    setIsConnecting(true);
    setIsLoading(true);

    const handleAgentData = (event: Event) => {
      try {
        const customEvent = event as CustomEvent<{
          stocks?: Props['stocks'];
          lastUpdated?: string;
        }>;
        const detail = customEvent?.detail;

        if (!detail || (detail.stocks !== undefined && !Array.isArray(detail.stocks))) {
          setConnectionError('Received malformed live update payload.');
          setIsConnecting(false);
          setIsLoading(false);
          return;
        }

        if (Array.isArray(detail?.stocks)) {
          setLiveStocks(detail.stocks);
        }

        if (typeof detail?.lastUpdated === 'string' && detail.lastUpdated) {
          setLiveLastUpdated(detail.lastUpdated);
        } else {
          setLiveLastUpdated(new Date().toISOString());
        }

        setConnectionError('');
        setIsConnecting(false);
        setIsLoading(false);
      } catch {
        setConnectionError('Unable to process live update.');
        setIsConnecting(false);
        setIsLoading(false);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formatTimestamp = (value?: string) => {
    if (!value) return '—';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleString();
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between" align="center" wrap>
          <Text variant="h1" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Text>
          <Stack gap={4} align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
              {formatTimestamp(liveLastUpdated)}
            </Text>
          </Stack>
        </Row>

        <Row
          align="center"
          gap={8}
          style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
          aria-live="polite"
        >
          {connectionError ? (
            <Badge variant="error">Error</Badge>
          ) : isConnecting ? (
            <Badge variant="warning">Connecting</Badge>
          ) : isLoading ? (
            <Badge variant="info">Loading</Badge>
          ) : (
            <Badge variant="success">Live</Badge>
          )}
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {connectionError
              ? connectionError
              : isConnecting
              ? 'Connecting to live market feed...'
              : isLoading
              ? 'Loading latest stock prices...'
              : 'Live updates active'}
          </Text>
        </Row>

        <Box
          role="list"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          {liveStocks.map((item, index) => {
            const symbol = item.symbol || '—';
            const name = item.name || 'Unknown Company';
            const price = item.price ?? 0;
            const change = item.change ?? 0;
            const changePercent = item.changePercent ?? 0;

            const isPositive = change > 0;
            const isNegative = change < 0;
            const directionColor = isPositive
              ? 'var(--ggui-color-success-500, #22c55e)'
              : isNegative
              ? 'var(--ggui-color-error-500, #ef4444)'
              : 'var(--ggui-color-onSurfaceVariant, #52525b)';
            const arrow = isPositive ? '▲' : isNegative ? '▼' : '•';
            const signedChange = `${change > 0 ? '+' : ''}${change.toFixed(2)}`;
            const signedPercent = `${changePercent > 0 ? '+' : ''}${changePercent.toFixed(2)}%`;
            const directionText = isPositive ? 'up' : isNegative ? 'down' : 'unchanged';

            return (
              <Card
                key={item.symbol || index}
                border
                shadow="sm"
                role="listitem"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: isPositive
                    ? 'var(--ggui-color-success-500, #22c55e)'
                    : isNegative
                    ? 'var(--ggui-color-error-500, #ef4444)'
                    : 'var(--ggui-color-outline, #d4d4d8)',
                  transition: 'color 200ms, background-color 200ms, border-color 200ms',
                  animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out both' : 'none',
                }}
              >
                <Stack gap={8}>
                  <Row justify="between" align="start">
                    <Stack gap={2}>
                      <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {symbol}
                      </Text>
                      <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {name}
                      </Text>
                    </Stack>
                    <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      ${price.toFixed(2)}
                    </Text>
                  </Row>

                  <Row justify="between" align="center">
                    <Text variant="body" color={directionColor}>
                      {signedChange}
                    </Text>
                    <Text variant="label" color={directionColor}>
                      {arrow} {signedPercent} ({directionText})
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Heading,
  Text,
  Badge,
  Divider,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action Contract callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

type FormData = {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
};

export default function GeneratedComponent(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();

  const getInitialFormData = (): FormData => ({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0] ?? '',
    role: initialProfile?.role ?? roleOptions[0] ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  const [currentStep, setCurrentStep] = useState<number>(0);
  const [formData, setFormData] = useState<FormData>(getInitialFormData);
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  useEffect(() => {
    setFormData(getInitialFormData());
    setErrors({});
  }, [initialProfile, avatarOptions, roleOptions]);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const validateStep1 = () => {
    const nextErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) nextErrors.name = 'Name is required';
    if (!formData.email.trim()) nextErrors.email = 'Email is required';
    else if (!emailRegex.test(formData.email.trim())) nextErrors.email = 'Invalid email format';

    const avatarValid = avatarOptions.length === 0 ? !!formData.avatar : avatarOptions.includes(formData.avatar);
    const valid = !nextErrors.name && !nextErrors.email && avatarValid;

    setErrors(nextErrors);
    return valid;
  };

  const validateStep2 = () => {
    const roleValid = roleOptions.includes(formData.role);
    const themeValid = formData.theme === 'light' || formData.theme === 'dark';
    return roleValid && themeValid && typeof formData.emailNotifications === 'boolean';
  };

  const isStepValid = useMemo(() => {
    if (currentStep === 0) {
      const nameOk = formData.name.trim().length > 0;
      const emailOk = formData.email.trim().length > 0 && emailRegex.test(formData.email.trim());
      const avatarOk = avatarOptions.length === 0 ? !!formData.avatar : avatarOptions.includes(formData.avatar);
      return nameOk && emailOk && avatarOk;
    }
    if (currentStep === 1) {
      const roleOk = roleOptions.includes(formData.role);
      const themeOk = formData.theme === 'light' || formData.theme === 'dark';
      return roleOk && themeOk;
    }
    return true;
  }, [currentStep, formData, avatarOptions, roleOptions]);

  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  const handleNext = () => {
    if (currentStep === 0 && !validateStep1()) return;
    if (currentStep === 1 && !validateStep2()) return;
    setCurrentStep((s) => Math.min(2, s + 1));
  };

  const handleBack = () => {
    setCurrentStep((s) => Math.max(0, s - 1));
  };

  const handleComplete = async () => {
    const valid = validateStep1() && validateStep2();
    if (!valid) return;
    setIsSubmitting(true);
    try {
      onComplete?.({
        name: formData.name.trim(),
        email: formData.email.trim(),
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="md" center padding={24}>
      <MotionKeyframes />
      <Card padding={24} shadow="sm" border>
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Onboarding Setup</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep + 1} of 3
            </Text>

            <Stack gap={12} aria-label="Onboarding progress">
              <Row justify="between" align="center" gap={8}>
                {steps.map((label, index) => {
                  const status = index < currentStep ? 'Completed' : index === currentStep ? 'Current' : 'Upcoming';
                  const variant =
                    index < currentStep ? 'success' : index === currentStep ? 'primary' : 'secondary';
                  return (
                    <Stack key={label} gap={4} align="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurface, #18181b)"
                        aria-current={index === currentStep ? 'step' : undefined}
                      >
                        {label}
                      </Text>
                      <Badge variant={variant}>{status}</Badge>
                    </Stack>
                  );
                })}
              </Row>

              <Box
                background="var(--ggui-color-outlineVariant, #e4e4e7)"
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
                style={{ width: '100%', height: '8px' }}
              >
                <Box
                  role="progressbar"
                  aria-valuemin={1}
                  aria-valuemax={3}
                  aria-valuenow={currentStep + 1}
                  background="var(--ggui-color-primary-600, #0284c7)"
                  borderRadius="var(--ggui-shape-radius-full, 9999px)"
                  style={{
                    width: `${(currentStep / 2) * 100}%`,
                    height: '100%',
                    transition: transition.normal,
                  }}
                />
              </Box>
            </Stack>
          </Stack>

          <Divider />

          <Box
            style={{
              animation: motionEnabled ? animation.slideInUp : 'none',
            }}
          >
            {currentStep === 0 && (
              <Stack gap={16}>
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(value) => {
                    setFormData((p) => ({ ...p, name: value }));
                    if (errors.name) setErrors((e) => ({ ...e, name: undefined }));
                  }}
                  required
                  error={errors.name}
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(value) => {
                    setFormData((p) => ({ ...p, email: value }));
                    if (errors.email) setErrors((e) => ({ ...e, email: undefined }));
                  }}
                  required
                  error={errors.email}
                />

                <Stack gap={8}>
                  <Text variant="label">Choose avatar</Text>
                  <Stack direction="horizontal" wrap gap={8} aria-label="Choose avatar">
                    {avatarOptions.map((avatar, index) => {
                      const selected = formData.avatar === avatar;
                      return (
                        <Button
                          key={`${avatar}-${index}`}
                          variant={selected ? 'primary' : 'ghost'}
                          size="lg"
                          aria-pressed={selected}
                          onClick={() => setFormData((p) => ({ ...p, avatar }))}
                        >
                          {avatar}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack gap={16}>
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(value) => setFormData((p) => ({ ...p, role: value }))}
                  options={roleOptions.map((role) => ({ value: role, label: role }))}
                  placeholder="Select role"
                  required
                />
                <Checkbox
                  label="Email notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => setFormData((p) => ({ ...p, emailNotifications: checked }))}
                  description="Receive onboarding and product updates via email."
                />
                <RadioGroup
                  label="Theme preference"
                  value={formData.theme}
                  onChange={(value) => setFormData((p) => ({ ...p, theme: value }))}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={12}>
                <Text variant="body" weight="semibold">
                  Review your setup
                </Text>
                <Row justify="between"><Text variant="label">Name</Text><Text variant="body">{formData.name}</Text></Row>
                <Row justify="between"><Text variant="label">Email</Text><Text variant="body">{formData.email}</Text></Row>
                <Row justify="between"><Text variant="label">Avatar</Text><Text variant="body">{formData.avatar}</Text></Row>
                <Row justify="between"><Text variant="label">Role</Text><Text variant="body">{formData.role}</Text></Row>
                <Row justify="between">
                  <Text variant="label">Email Notifications</Text>
                  <Text variant="body">{formData.emailNotifications ? 'On' : 'Off'}</Text>
                </Row>
                <Row justify="between"><Text variant="label">Theme</Text><Text variant="body">{formData.theme}</Text></Row>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between" align="center" gap={12}>
            <Button
              variant="outline"
              onClick={handleBack}
              disabled={currentStep === 0 || isSubmitting}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              {currentStep === 2 ? 'Go Back' : 'Back'}
            </Button>

            {currentStep < 2 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!isStepValid || isSubmitting}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleComplete}
                loading={isSubmitting}
                disabled={isSubmitting}
              >
                Complete Setup
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import {
