/**
 * WeatherCard Component
 * Displays current weather conditions and a 5-day forecast using GGUI primitives.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 45,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '⛅', high: 72, low: 58 },
    { day: 'Wed', icon: '☁️', high: 68, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 65, low: 52 },
    { day: 'Fri', icon: '☀️', high: 70, low: 57 },
  ],
}: Props) {
  const { motionEnabled } = useMotion();

  // Helper to determine weather emoji if not provided by prop
  const conditionEmoji = (cond: string) => {
    const lower = cond.toLowerCase();
    if (lower.includes('sun')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('storm')) return '⛈️';
    return '⛅';
  };

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        border
        style={{
          background: 'var(--ggui-color-surface, #ffffff)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
          maxWidth: '450px',
          margin: '0 auto',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}
      >
        <Stack gap={24}>
          {/* Header Section: City and Date */}
          <Stack gap={4} align="center">
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>

          {/* Main Temperature Display */}
          <Row justify="center" align="center" gap={24}>
            <span style={{ fontSize: '64px', lineHeight: 1 }} aria-hidden="true">
              {conditionEmoji(condition)}
            </span>
            <Stack gap={0}>
              <Row align="start" gap={2}>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 48px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    lineHeight: 1,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {Math.round(temperature)}
                </Text>
                <Text variant="h3" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginTop: '4px' }}>
                  {unit}
                </Text>
              </Row>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* Weather Details: Humidity & Wind */}
          <Row justify="around" align="center">
            <Stack align="center" gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>

            <div style={{ width: '1px', height: '32px', background: 'var(--ggui-color-outlineVariant, #e4e4e7)' }} />

            <Stack align="center" gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND SPEED
              </Text>
              <Text weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} mph
              </Text>
            </Stack>
          </Row>

          {/* 5-Day Forecast Strip */}
          <Box
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            padding={16}
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Row justify="between" gap={8} align="stretch">
              {forecast.slice(0, 5).map((item, index) => (
                <Stack 
                  key={item.day || index} 
                  align="center" 
                  gap={8} 
                  style={{ 
                    flex: 1,
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: `${index * 50}ms`,
                  }}
