                      {item.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ opacity: 0.7 }}>
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Box>
        </Stack>
      </Card>
    </Box>
  );
