import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  /** Action Contract: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
  taskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

/**
 * KanbanBoard Component
 * A robust task management interface with column-based workflow,
 * inline editing, and task creation.
 */
export default function GeneratedComponent(props: Props) {
  const { tasks: initialTasks = [], columns = [], taskUpdate } = props;

  const [tasks, setTasks] = useState(initialTasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitleValue, setEditTitleValue] = useState('');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const { motionEnabled } = useMotion();

  // Sync state with props
  useEffect(() => {
    setTasks(initialTasks);
  }, [initialTasks]);

  const handleAction = (action: string, taskId?: string, data?: any) => {
    if (taskUpdate) {
      taskUpdate({ action, taskId, data });
    }
  };

  const handleMoveTask = (taskId: string, newColumnId: string) => {
    const updatedTasks = tasks.map(t => (t.id === taskId ? { ...t, column: newColumnId } : t));
    setTasks(updatedTasks);
    handleAction('move', taskId, { column: newColumnId });
  };

  const handleSaveEdit = (taskId: string) => {
    if (!editTitleValue.trim()) return;
    const updatedTasks = tasks.map(t => (t.id === taskId ? { ...t, title: editTitleValue } : t));
    setTasks(updatedTasks);
    setEditingTaskId(null);
    handleAction('edit', taskId, { title: editTitleValue });
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: 'ME',
      dueDate: new Date().toISOString().split('T')[0]
    };
    setTasks(prev => [...prev, newTask]);
    setAddingToColumn(null);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    handleAction('create', undefined, newTask);
  };

  const totalTasks = tasks.length;
  const lastColId = columns.length > 0 ? columns[columns.length - 1].id : 'done';
  const completedCount = tasks.filter(t => t.column === lastColId).length;

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'default';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Summary Dashboard Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row align="center" justify="between" wrap gap={16}>
            <Stack direction="horizontal" gap={16} align="center">
              <Heading level={2}>Board Overview</Heading>
              <Divider orientation="vertical" margin={8} />
              <Row gap={12}>
                <Badge variant="primary" size="lg">Total: {totalTasks}</Badge>
                <Badge variant="success" size="lg">Completed: {completedCount}</Badge>
              </Row>
            </Stack>
            <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-2) var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Double-click a title to edit task details
              </Text>
            </Box>
          </Row>
        </Card>

        {/* The Kanban Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: `repeat(${columns.length || 3}, 1fr)`,
          gap: 'var(--ggui-spacing-6)',
          alignItems: 'start',
          overflowX: 'auto',
          minHeight: '70vh'
        }}>
          {columns.map((col) => {
            const columnTasks = tasks.filter(t => t.column === col.id);
            return (
              <Box
                key={col.id}
                padding="var(--ggui-spacing-4)"
                borderRadius="var(--ggui-shape-radius-lg)"
                background="var(--ggui-color-surfaceVariant)"
                style={{
                  minWidth: '320px',
                  display: 'flex',
                  flexDirection: 'column',
                  border: '1px solid var(--ggui-color-outlineVariant)',
                  transition: transition.colors
                }}
              >
                {/* Column Heading */}
                <Row justify="between" align="center" style={{ marginBottom: 'var(--ggui-spacing-4)' }}>
                  <Heading level={4}>{col.name}</Heading>
                  <Badge variant="secondary" pill>{columnTasks.length}</Badge>
                </Row>

                {/* Tasks Stack */}
                <Stack gap={12} style={{ flexGrow: 1 }}>
                  {columnTasks.map((task, index) => (
                    <Card
                      key={task.id}
                      padding="var(--ggui-spacing-4)"
                      shadow="sm"
                      style={{
                        animation: motionEnabled ? animation.fadeIn : 'none',
                        animationDelay: `${index * 50}ms`,
                        backgroundColor: 'var(--ggui-color-surface)',
                        border: '1px solid var(--ggui-color-outlineVariant)'
                      }}
                    >
                      <Stack gap={12}>
                        {/* Task Title & Edit UI */}
                        {editingTaskId === task.id ? (
                          <Stack gap={8}>
                            <Input
                              label="Edit Task"
                              value={editTitleValue}
                              onChange={setEditTitleValue}
                              placeholder="Update title..."
                            />
                            <Row gap={8} justify="end">
                              <Button size="xs" variant="ghost" onClick={() => setEditingTaskId(null)}>Cancel</Button>
                              <Button size="xs" variant="primary" onClick={() => handleSaveEdit(task.id!)}>Save</Button>
                            </Row>
                          </Stack>
                        ) : (
                          <Row justify="between" align="start">
                            <Text
                              weight="medium"
                              style={{ flexGrow: 1, cursor: 'text' }}
                              onDoubleClick={() => {
                                setEditingTaskId(task.id!);
                                setEditTitleValue(task.title || '');
                              }}
                            >
                              {task.title}
                            </Text>
                            <Button
                              size="xs"
                              variant="ghost"
                              onClick={() => {
                                setEditingTaskId(task.id!);
                                setEditTitleValue(task.title || '');
                              }}
                              aria-label="Edit Task"
                            >
                              <Icon name="settings" size={14} />
                            </Button>
                          </Row>
                        )}

                        {/* Task Footer Meta */}
                        <Row align="center" justify="between">
                          <Row gap={8} align="center">
                            <Badge variant={getPriorityVariant(task.priority)} size="sm">
                              {task.priority || 'medium'}
                            </Badge>
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {task.dueDate}
                              </Text>
                            )}
                          </Row>
                          <div
                            title={`Assignee: ${task.assignee}`}
                            style={{
                              width: 32,
                              height: 32,
                              borderRadius: 'var(--ggui-shape-radius-full)',
                              background: 'var(--ggui-color-primary-100)',
                              color: 'var(--ggui-color-primary-700)',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              fontSize: '12px',
                              fontWeight: 'var(--ggui-font-weight-bold)',
                              border: '2px solid var(--ggui-color-surface)'
                            }}
                          >
                            {task.assignee}
                          </div>
                        </Row>

                        <Divider margin={4} />

                        {/* Move Control */}
                        <Select
                          label="Change Column"
                          value={task.column || ''}
                          onChange={(val) => handleMoveTask(task.id!, val)}
                          options={columns.map(c => ({ value: c.id || '', label: `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {/* Create Task Form */}
                <Box style={{ marginTop: 'var(--ggui-spacing-4)' }}>
                  {addingToColumn === col.id ? (
                    <Card padding="var(--ggui-spacing-4)" border style={{ borderColor: 'var(--ggui-color-primary-300)' }}>
                      <Stack gap={12}>
                        <Input
                          label="Task Name"
                          placeholder="What's the task?"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          required
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val: any) => setNewTaskPriority(val)}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' }
                          ]}
                        />
                        <Row gap={8} justify="end">
                          <Button size="sm" variant="ghost" onClick={() => setAddingToColumn(null)}>
                            Cancel
                          </Button>
                          <Button size="sm" variant="primary" onClick={() => handleAddTask(col.id!)} disabled={!newTaskTitle.trim()}>
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      fullWidth
                      variant="ghost"
                      size="lg"
                      leftIcon={<Icon name="plus" size={20} />}
                      onClick={() => setAddingToColumn(col.id!)}
                    >
                      New Task
                    </Button>
                  )}
                </Box>
              </Box>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

/**
 * Metadata for GGUI registry
 */
export const __GGUI_META__ = {
  category: 'Data Management',
  description: 'A fully interactive Kanban board with multi-column task tracking, inline editing, and priority management.',
  version: '1.0.0'
};

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Badge,
  Box,
  Divider,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to theme-aware design token colors.
 * These semantic tokens adapt to light/dark themes.
 */
const getCategoryColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-200, #fecaca)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-200, #fef08a)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-200, #e5e7eb)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-success-200, #bbf7d0)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-200, #a5f3fc)';
  if (cat.includes('halogen')) return 'var(--ggui-color-warning-300, #fde047)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-300, #86efac)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-100, #fee2e2)';
  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(lowerSearch) ||
        el.symbol?.toLowerCase().includes(lowerSearch)
    );
  }, [elements, searchTerm]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={16} align="center">
          <Text variant="h1" align="center">Periodic Table of Elements</Text>
          <Box style={{ width: '100%', maxWidth: 480 }}>
            <Text as="label" htmlFor="periodic-search-field" variant="label">Search Elements</Text>
            <Input label="Search Elements" id="periodic-search-field" value={searchTerm} onChange={setSearchTerm} placeholder="Filter by name or symbol..." leftIcon={<Icon name="search" size={18} />} />
          </Box>
        </Stack>

        <Card border={false} padding="var(--ggui-spacing-2, 8px)">
          <Row wrap gap={12} justify="center">
            {categories.map((cat) => (
              <Row key={cat} gap={8} align="center">
                <Box
                  style={{
                    width: 'var(--ggui-spacing-3, 12px)',
                    height: 'var(--ggui-spacing-3, 12px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    backgroundColor: getCategoryColor(cat),
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                />
                <Text variant="caption" weight="medium">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-10, 40px), 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          {elements.map((el) => {
            const isHighlighted = searchTerm === '' || filteredElements.some(f => f.atomicNumber === el.atomicNumber);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <Box
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: getCategoryColor(el.category),
                  border: isSelected
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                    : '1px solid var(--ggui-color-outline, #d4d4d8)',
                  opacity: isHighlighted ? 1 : 0.2,
                  cursor: 'pointer',
                  transition: transition.normal,
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  transform: isSelected ? 'scale(1.1)' : 'none',
                  zIndex: isSelected ? 10 : 1,
                  position: 'relative',
                }}
              >
                <Text
                  style={{
                    fontSize: '10px',
                    position: 'absolute',
                    top: 'var(--ggui-spacing-1, 4px)',
                    left: 'var(--ggui-spacing-1, 4px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    pointerEvents: 'none',
                  }}
                >
                  {el.atomicNumber}
                </Text>
                <Stack align="center" justify="center" style={{ height: '100%' }} gap={0}>
                  <Text weight="bold" style={{ fontSize: '1rem', lineHeight: 1 }}>
                    {el.symbol}
                  </Text>
                </Stack>
              </Box>
            );
          })}
        </Box>

        <Box style={{ minHeight: 'var(--ggui-spacing-48, 192px)' }}>
          {selectedElement ? (
            <Card
              padding="var(--ggui-spacing-6, 24px)"
              style={{
                animation: motionEnabled ? animation.slideInUp : 'none',
                borderLeft: `12px solid ${getCategoryColor(selectedElement.category)}`,
