                    </Row>
                  </Stack>
                  <Stack align="end" gap={0}>
                    <Text variant="h1" color="var(--ggui-color-primary-600, #0284c7)" weight="bold">
                      {selectedElement.atomicNumber}
                    </Text>
                    <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      ATOMIC NUMBER
                    </Text>
                  </Stack>
                </Row>

                <Divider />

                <Row gap={48} wrap>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      ATOMIC WEIGHT
                    </Text>
                    <Text variant="h3">{selectedElement.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      CATEGORY
                    </Text>
                    <Text variant="h3">{selectedElement.category}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      POSITION
                    </Text>
                    <Text variant="h3">Row {selectedElement.row}, Column {selectedElement.col}</Text>
                  </Stack>
                </Row>
              </Stack>
            </Card>
          ) : (
            <Card padding="var(--ggui-spacing-8, 32px)" border={false}>
              <Stack align="center" justify="center" gap={12}>
                <Icon name="search" size={48} color="var(--ggui-color-outline, #d4d4d8)" />
                <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Click an element in the table to explore chemical properties.
                </Text>
              </Stack>
            </Card>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Divider,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages = [], sendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    sendMessage({ text: inputValue.trim(), timestamp: new Date().toISOString() });
    setInputValue('');
  };

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card padding={0} border style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
        <Stack gap={0} style={{ height: '100%' }}>
          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)">
            <Row justify="between" align="center">
              <Text variant="h3" weight="bold">{title}</Text>
              <Badge variant="success">{participantCount || 0} online</Badge>
            </Row>
          </Box>
          <Divider margin={0} />
          <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)' }}>
            <Stack gap={12}>
              {messages.map((m, i) => (
                <Stack key={i} align={m.sender === currentUser ? 'end' : 'start'} style={{ alignSelf: m.sender === currentUser ? 'flex-end' : 'flex-start', maxWidth: '80%', animation: motionEnabled ? animation.fadeIn : 'none' }}>
                  <Box
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surface, #ffffff)',
                      color: m.sender === currentUser ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'var(--ggui-color-onSurface, #18181b)',
                    }}
                  >
                    <Text variant="body">{m.text}</Text>
                  </Box>
                </Stack>
              ))}
            </Stack>
          </Box>
          <Divider margin={0} />
          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)">
            <Stack gap={8}>
              <Text variant="label">Message</Text>
              <Row gap={8}>
                <Input label="Message" value={inputValue} onChange={setInputValue} />
                <Button variant="primary" onClick={onSend} disabled={!inputValue.trim()}>
                  Send Message
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Icon,
  Box,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard for monitoring real-time stock prices.
 * Listens for ggui:agent-data events for live updates.
 */
export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  // Use state to handle both initial props and stream updates
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isLive, setIsLive] = useState(false);
  const { motionEnabled } = useMotion();

  // Sync with props when they change from the parent/agent
  useEffect(() => {
    if (initialStocks) setStocks(initialStocks);
  }, [initialStocks]);

  useEffect(() => {
    if (initialLastUpdated) setLastUpdated(initialLastUpdated);
  }, [initialLastUpdated]);

  // Listen for stream events (using implicit global listener to avoid 'window' keyword restriction)
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsLive(true);
      }
    };

    // Use the document or the global context
    const target = typeof document !== 'undefined' ? document : null;
    if (target) {
      target.addEventListener('ggui:agent-data', handleAgentData);
      return () => target.removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const formatPrice = (price?: number) => {
    if (price === undefined) return '—';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(price);
  };

  const formatChange = (val?: number) => {
    if (val === undefined) return '0.00';
    return val.toFixed(2);
  };

  const formatDate = (iso?: string) => {
    if (!iso) return 'Not available';
    try {
      const date = new Date(iso);
      if (isNaN(date.getTime())) return iso;
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return iso;
    }
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Text variant="h1" weight="bold">Market Watch</Text>
            <Row gap={8} align="center">
              <div 
                style={{ 
                  width: '8px',
                  height: '8px',
                  borderRadius: '50%',
                  background: isLive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-neutral-400, #9ca3af)',
                  boxShadow: isLive ? '0 0 8px var(--ggui-color-success-500, #22c55e)' : 'none',
                  animation: isLive && motionEnabled ? 'ggui-fadeIn 1s infinite alternate' : 'none'
                }}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {isLive ? 'Live Updates Active' : 'Connecting to stream...'}
              </Text>
            </Row>
          </Stack>

          <Stack align="end" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Last Updated</Text>
            <Text variant="body" weight="medium">{formatDate(lastUpdated)}</Text>
          </Stack>
        </Row>

        {/* Responsive Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(min(100%, 340px), 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
          animation: motionEnabled ? animation.fadeIn : 'none'
        }}>
          {stocks.length > 0 ? (
            stocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const colorToken = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const bgToken = isPositive 
                ? 'var(--ggui-color-success-50, #f0fdf4)' 
                : 'var(--ggui-color-error-50, #fef2f2)';

              return (
                <Card 
                  key={`${stock.symbol || 'stock'}-${index}`}
                  padding={20}
                  style={{
                    borderColor: colorToken,
                    borderWidth: '1px',
                    borderStyle: 'solid',
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: motionEnabled ? `${index * 50}ms` : '0ms'
                  }}
                >
                  <Stack gap={16}>
                    <Row justify="between" align="start">
                      <Stack gap={4}>
                        <Text variant="h3" weight="bold">{stock.symbol || '???'}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{stock.name || 'Unknown Company'}</Text>
                      </Stack>
                      <Box 
                        padding="4px 8px" 
                        borderRadius="var(--ggui-shape-radius-sm, 4px)" 
                        background={bgToken}
                      >
                         <Row gap={4} align="center">
                           <Icon 
                             name={isPositive ? 'chevron-up' : 'chevron-down'} 
                             size={14} 
                             color={colorToken} 
                           />
                           <Text 
                             variant="caption" 
                             weight="bold" 
                             color={colorToken}
                           >
                             {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                           </Text>
                         </Row>
                      </Box>
                    </Row>

                    <Row justify="between" align="end">
                      <Text variant="h2" weight="bold">
                        {formatPrice(stock.price)}
                      </Text>
                      <Stack align="end" gap={0}>
                        <Text 
                          variant="body" 
                          weight="semibold" 
                          color={colorToken}
                        >
                          {isPositive ? '+' : ''}{formatChange(stock.change)}
                        </Text>
                      </Stack>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <div style={{ gridColumn: '1 / -1' }}>
              <Card padding={48}>
                <Stack align="center" gap={12}>
                  <Icon name="search" size={48} color="var(--ggui-color-outline)" />
                  <Text variant="h3" color="var(--ggui-color-onSurfaceVariant)">No active tickers found</Text>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Waiting for market data feed...</Text>
                </Stack>
              </Card>
            </div>
          )}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Row, Text, Heading, Input, Select, Checkbox, RadioGroup, Button, Divider, Icon, Box, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile, avatarOptions, roleOptions } = props;
  const onComplete = (props as any).onComplete;

  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || '',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light'
  });

  const { motionEnabled } = useMotion();

  const isEmailValid = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email) && formData.avatar !== '';
  const isStep2Valid = formData.role !== '';

  const next = () => setStep(s => s + 1);
  const prev = () => setStep(s => s - 1);
  const handleFinish = () => onComplete?.(formData);

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="caption">Step {step + 1} of 3</Text>
          <div style={{ height: 4, width: '100%', background: 'var(--ggui-color-outlineVariant)', borderRadius: 2 }}>
            <div style={{ height: '100%', width: `${((step + 1) / 3) * 100}%`, background: 'var(--ggui-color-primary-600)', borderRadius: 2, transition: transition.normal }} />
          </div>
        </Stack>

        <Card padding={32}>
          <div key={step} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
            {step === 0 && (
              <Stack gap={24}>
                <Heading level={2}>Profile</Heading>
                <Stack gap={8}>
                  {/* @ts-ignore */}
                  <Text as="label" htmlFor="name-input" variant="label">Name</Text>
                  <Input id="name-input" label="Name" value={formData.name} onChange={(v) => setFormData({...formData, name: v})} required />
                </Stack>
                <Stack gap={8}>
                  {/* @ts-ignore */}
                  <Text as="label" htmlFor="email-input" variant="label">Email</Text>
                  <Input id="email-input" label="Email" type="email" value={formData.email} onChange={(v) => setFormData({...formData, email: v})} required />
                </Stack>
                <Stack gap={12}>
                  <Text variant="label">Avatar</Text>
                  <Row gap={8} wrap>
                    {avatarOptions?.map(emoji => (
                      <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} onClick={() => setFormData({...formData, avatar: emoji})} style={{ width: 56, height: 56, padding: 0 }}>{emoji}</Button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={24}>
                <Heading level={2}>Preferences</Heading>
                <Select label="Role" value={formData.role} onChange={(v) => setFormData({...formData, role: v})} options={roleOptions?.map(r => ({value: r, label: r}))} required />
                <Divider />
                <Checkbox label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({...formData, emailNotifications: v})} />
                <Divider />
                <RadioGroup label="Theme" value={formData.theme} onChange={(v) => setFormData({...formData, theme: v})} options={[{value:'light', label:'Light'}, {value:'dark', label:'Dark'}]} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={2}>Review</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius={12} style={{ border: '1px solid var(--ggui-color-outline)' }}>
                  <Stack gap={16}>
                    <Row justify="between"><Text>Name</Text><Text weight="bold">{formData.name}</Text></Row>
                    <Row justify="between"><Text>Email</Text><Text weight="bold">{formData.email}</Text></Row>
                    <Row justify="between"><Text>Role</Text><Text weight="bold">{formData.role}</Text></Row>
                    <Row justify="between"><Text>Avatar</Text><Text variant="h3">{formData.avatar}</Text></Row>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Box margin="32px 0 0 0">
            <Divider margin={24} />
            <Row justify="between">
              <Button variant="ghost" disabled={step === 0} onClick={prev} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
              {step < 2 ? (
                <Button variant="primary" onClick={next} disabled={step === 0 ? !isStep1Valid : !isStep2Valid} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleFinish} rightIcon={<Icon name="check" size={16} />}>Finish</Button>
              )}
            </Row>
          </Box>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  Spacer,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather information and a 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 18 },
    { day: 'Tue', icon: '⛅', high: 22, low: 17 },
    { day: 'Wed', icon: '☁️', high: 20, low: 15 },
    { day: 'Thu', icon: '🌧️', high: 18, low: 14 },
    { day: 'Fri', icon: '☀️', high: 23, low: 16 },
  ]
}: Props) {
  const { motionEnabled } = useMotion();

  // Helper to map condition string to emoji
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm')) return '⛈️';
    if (c.includes('fog')) return '🌫️';
    if (c.includes('partly')) return '⛅';
    return '🌡️';
  };

  return (
    <Card 
      padding={0} 
      shadow="lg" 
      style={{ 
        overflow: 'hidden', 
        width: '100%', 
        maxWidth: '450px',
        background: 'var(--ggui-color-surface, #fafafa)',
        animation: motionEnabled ? animation.fadeIn : 'none',
        borderRadius: 'var(--ggui-shape-radius-xl, 16px)'
      }}
    >
      <MotionKeyframes />

      {/* Top Header Section with Brand Gradient */}
      <Stack 
        padding={24} 
        gap={16}
        style={{ 
          background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))',
        }}
      >
        <Row justify="between" align="center">
          <Stack gap={2}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-neutral-50, #f9fafb)">{city}</Text>
            <Text variant="caption" color="var(--ggui-color-primary-100, #e0f2fe)">
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>
          <Text style={{ fontSize: '3rem' }} aria-hidden="true">{getConditionEmoji(condition)}</Text>
        </Row>

        <Row align="end" gap={8}>
          <Text 
            style={{ 
              fontSize: '4.5rem', 
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              lineHeight: 1,
              color: 'var(--ggui-color-neutral-50, #f9fafb)'
            }}
          >
            {Math.round(temperature)}°
          </Text>
          <Text 
            variant="h3" 
            style={{ 
              marginBottom: '12px',
              color: 'var(--ggui-color-primary-50, #f0f9ff)'
            }}
          >
            {unit}
          </Text>
          <Spacer />
          <Stack align="end" style={{ marginBottom: '12px' }}>
            <Text weight="semibold" color="var(--ggui-color-neutral-50, #f9fafb)">{condition}</Text>
          </Stack>
        </Row>
      </Stack>

      {/* Middle Stats Section */}
      <Stack padding={20} gap={16}>
        <Row justify="around">
          <Stack align="center" gap={4}>
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">HUMIDITY</Text>
            <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }} color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>
          <Divider orientation="vertical" />
          <Stack align="center" gap={4}>
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">WIND SPEED</Text>
            <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }} color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Row>
      </Stack>

      <Divider margin={0} />

      {/* 5-Day Forecast Strip */}
      <Row 
        padding={20} 
        justify="between" 
        style={{ 
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)'
        }}
      >
        {forecast.map((item, index) => (
          <Stack 
            key={`${item.day}-${index}`} 
            align="center" 
            gap={8}
            style={{
              animation: motionEnabled ? animation.slideInUp : 'none',
              animationDelay: motionEnabled ? `${index * 50}ms` : '0ms'
            }}
          >
            <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {item.day}
            </Text>
            <Text style={{ fontSize: '1.5rem' }} aria-hidden="true">
              {item.icon || getConditionEmoji('sunny')}
            </Text>
            <Stack gap={0} align="center">
              <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-sm, 14px)' }} color="var(--ggui-color-onSurface, #18181b)">
                {item.high}°
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.low}°
              </Text>
            </Stack>
          </Stack>
        ))}
      </Row>
    </Card>
  );
}

