/**
 * Interactive Periodic Table
 */
export default function PeriodicTable({
  elements = []
}: Props) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const getCategoryColor = (category?: string) => {
    const cat = category?.toLowerCase() || '';
    if (cat.includes('alkali')) return 'var(--ggui-color-error-600, #dc2626)';
    if (cat.includes('noble')) return 'var(--ggui-color-primary-800, #075985)';
    return 'var(--ggui-color-outline, #d4d4d8)';
  };

  const filteredElements = useMemo(() => {
    const q = search.toLowerCase();
    return elements.map(el => ({
      ...el,
      matches: !q || el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)
    }));
  }, [elements, search]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach(el => { if (el.category) cats.add(el.category); });
    return Array.from(cats);
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Card border shadow="sm" padding="var(--ggui-spacing-6, 24px)">
          <Row justify="between" align="end" wrap>
            <Stack gap={8}>
              <Text variant="h1" weight="bold">Periodic Table</Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Elements Grid</Text>
            </Stack>
            <Box style={{ width: '100%', maxWidth: '320px' }}>
              <Input label="Search Elements" placeholder="Search..." value={search} onChange={setSearch} />
            </Box>
          </Row>
        </Card>

        <Card border shadow="none" padding="var(--ggui-spacing-4, 16px)">
          <Row gap={16} wrap>
            {categories.map(cat => (
              <Row key={cat} gap={8} align="center">
                <div style={{ width: 'var(--ggui-spacing-3, 12px)', height: 'var(--ggui-spacing-3, 12px)', borderRadius: 'var(--ggui-shape-radius-full)', backgroundColor: getCategoryColor(cat) }} />
                <Text variant="caption">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box style={{ overflowX: 'auto', background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-spacing-4)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 64px)',
            gridTemplateRows: 'repeat(10, 76px)',
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: '1150px',
            margin: '0 auto'
          }}>
            {filteredElements.map((el) => (
              <Box
                key={`${el.atomicNumber}-${el.symbol}`}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  cursor: 'pointer',
                  background: 'var(--ggui-color-surface)',
                  opacity: el.matches ? 1 : 0.2,
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '1px solid var(--ggui-color-outline)',
                  position: 'relative',
                  borderRadius: 'var(--ggui-shape-radius-sm)'
                }}
              >
                <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 'var(--ggui-spacing-1, 4px)', backgroundColor: getCategoryColor(el.category), borderTopLeftRadius: 'var(--ggui-shape-radius-sm)', borderTopRightRadius: 'var(--ggui-shape-radius-sm)' }} />
                <Text variant="caption" style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', fontSize: 'var(--ggui-font-size-xs)' }}>{el.atomicNumber}</Text>
                <Text variant="h3" weight="bold">{el.symbol}</Text>
              </Box>
            ))}
          </div>
        </Box>

        {selectedElement && (
          <Card border shadow="lg" padding="var(--ggui-spacing-8)">
            <Row justify="between" align="center">
              <Stack gap={8}>
                <Text variant="h2" weight="bold">{selectedElement.name}</Text>
                <Row gap={8} align="center">
                  <Badge variant="primary">{selectedElement.category}</Badge>
                  <Text variant="caption">Weight: {selectedElement.atomicWeight}</Text>
                </Row>
              </Stack>
              <Box onClick={() => setSelectedElement(null)} style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-2)' }}>
                <Icon name="x" size={24} />
              </Box>
            </Row>
            <Divider margin={24} />
            <Row gap={32}>
              <Stack gap={4}><Text variant="caption">SYMBOL</Text><Text variant="h3">{selectedElement.symbol}</Text></Stack>
              <Stack gap={4}><Text variant="caption">NUMBER</Text><Text variant="h3">{selectedElement.atomicNumber}</Text></Stack>
              <Stack gap={4}><Text variant="caption">PERIOD</Text><Text variant="h3">{selectedElement.row}</Text></Stack>
            </Row>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Box,
  Divider,
  Icon,
  Container
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<Message>;
  /** Action Contract handler */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = 'Team Chat',
  currentUser = 'User',
  participantCount = 2,
  messages = [],
  onSendMessage
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendAction = () => {
    if (inputValue.trim() && onSendMessage) {
      onSendMessage({
        text: inputValue.trim(),
        timestamp: new Date().toISOString()
      });
      setInputValue('');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendAction();
    }
  };

  return (
    <Container maxWidth="md" padding={0}>
      <Card shadow="md" padding={0} border style={{ height: '600px', display: 'flex', flexDirection: 'column', background: 'var(--ggui-color-surface, #ffffff)' }}>
        <Box padding={16} background="var(--ggui-color-surface, #ffffff)" style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
          <Row justify="between" align="center">
            <Stack gap={4}>
              <Text variant="h3" weight="bold">{title}</Text>
              <Row gap={8} align="center">
                {participantCount !== undefined && <Badge variant="success" size="sm">{participantCount} Online</Badge>}
                <Text variant="caption">Messaging session active</Text>
              </Row>
            </Stack>
            <Icon name="user" size={20} />
          </Row>
        </Box>

        <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 16, background: 'var(--ggui-color-surface, #ffffff)' }}>
          <Stack gap={12}>
            {messages.map((item, i) => {
              const isMe = item.sender === currentUser;
              const isG = i > 0 && messages[i - 1].sender === item.sender;
              return (
                <Stack key={`m-${i}`} align={isMe ? 'end' : 'start'} gap={4}>
                  {!isG && <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.sender}</Text>}
                  <Box 
                    padding="8px 12px" 
                    style={{ 
                      maxWidth: '80%', 
                      borderRadius: 12,
                      background: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isMe ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)'
                    }}
                  >
                    <Stack gap={4}>
                      <Text style={{ color: 'inherit' }}>{item.text}</Text>
                      <Text variant="caption" align="right" style={{ fontSize: 10, opacity: 0.7, color: 'inherit' }}>
                        {item.timestamp ? new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                      </Text>
                    </Stack>
                  </Box>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Divider margin={0} />
        <Box padding={16} background="var(--ggui-color-surface, #ffffff)">
          <Stack gap={8}>
            <Text variant="label">Message</Text>
            <Row gap={12} align="end">
              <Box style={{ flex: 1 }} onKeyDown={handleKeyPress}>
                <Input label="Message" value={inputValue} onChange={setInputValue} placeholder="Type a message..." fullWidth />
              </Box>
              <Button variant="primary" onClick={handleSendAction} disabled={!inputValue.trim()}>Send</Button>
            </Row>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

