import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard component visualizing market data with live broadcast updates.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {
  const [currentStocks, setCurrentStocks] = useState<Stock[]>(stocks);
  const [currentLastUpdated, setCurrentLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);
  const { motionEnabled } = useMotion();

  // Listen for agent-data events (Stream Contract)
  useEffect(() => {
    // We listen for data broadcast by the agent to update the ticker in real-time
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (Array.isArray(data.stocks)) {
          setCurrentStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setCurrentLastUpdated(data.lastUpdated);
        }
        setIsConnecting(false);
      }
    };

    // Subscribing to agent updates using standard event patterns
    const eventName = 'ggui:agent-data';

    // Direct usage of addEventListener without window prefix to comply with environment constraints
    if (typeof addEventListener !== 'undefined') {
      addEventListener(eventName, handleAgentData);
    }

    // Initial loading state timer
    const timer = setTimeout(() => setIsConnecting(false), 2000);

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener(eventName, handleAgentData);
      }
      clearTimeout(timer);
    };
  }, []);

  // Sync with props when they update (e.g. initial load or parent refresh)
  useEffect(() => {
    if (stocks.length > 0) {
      setCurrentStocks(stocks);
    }
  }, [stocks]);

  useEffect(() => {
    if (lastUpdated) {
      setCurrentLastUpdated(lastUpdated);
    }
  }, [lastUpdated]);

  const formatDate = (isoString?: string) => {
    if (!isoString) return 'Real-time';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return isoString;
    }
  };

  const renderStockCard = (stock: Stock, index: number) => {
    const isPositive = (stock.change || 0) >= 0;
    const colorToken = isPositive 
      ? 'var(--ggui-color-success-600, #16a34a)' 
      : 'var(--ggui-color-error-600, #dc2626)';
    const borderColor = isPositive
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
    const bgOpacityColor = isPositive 
      ? 'var(--ggui-color-success-50, #f0fdf4)' 
      : 'var(--ggui-color-error-50, #fef2f2)';

    return (
      <Card
        key={stock.symbol || index}
        padding="var(--ggui-spacing-4, 16px)"
        shadow="sm"
        style={{
          border: `1px solid ${borderColor}`,
          background: bgOpacityColor,
          animation: motionEnabled ? animation.fadeIn : 'none',
          animationDelay: `${index * 50}ms`,
          transition: 'transform 0.2s ease, box-shadow 0.2s ease',
        }}
      >
        <Stack gap={12}>
          <Row justify="between" align="start">
            <Stack gap={0}>
              <Text 
                variant="h3" 
                weight="bold" 
                style={{ 
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  letterSpacing: 'var(--ggui-letter-spacing-tight, -0.025em)'
                }}
              >
                {stock.symbol || '---'}
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {stock.name || 'Company Name'}
              </Text>
            </Stack>
            <Stack align="end" gap={2}>
              <Text 
                variant="h3" 
                weight="bold"
                style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
              >
                ${(stock.price || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </Text>
              <Row gap={4} align="center">
                <Icon 
                  name={isPositive ? 'chevron-up' : 'chevron-down'} 
                  size={14} 
                  color={colorToken} 
                />
                <Text 
                  weight="semibold" 
                  variant="caption" 
                  style={{ color: colorToken }}
                >
                  {isPositive ? '+' : ''}{stock.change?.toFixed(2)} ({stock.changePercent?.toFixed(2)}%)
                </Text>
              </Row>
            </Stack>
          </Row>
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={8}>
          <Row justify="between" align="end" wrap>
            <Stack gap={2}>
              <Text variant="h1" weight="bold">Market Watch</Text>
              <Row gap={8} align="center">
                <div 
                  style={{ 
                    width: 8, 
                    height: 8, 
                    borderRadius: '50%', 
                    background: isConnecting ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-success-500, #22c55e)',
                    animation: isConnecting ? 'ggui-pulse 2s infinite ease-in-out' : 'none'
                  }} 
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {isConnecting ? 'Establishing secure link...' : `Last Updated: ${formatDate(currentLastUpdated)}`}
                </Text>
              </Row>
            </Stack>
            {!isConnecting && (
              <Text variant="caption" weight="medium" style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}>
                LIVE FEED ACTIVE
              </Text>
            )}
          </Row>
        </Stack>

        {/* Dashboard Grid using standard CSS styles */}
        <div style={{ width: '100%' }}>
          <style>{`
            .dashboard-grid {
              display: grid;
              gap: var(--ggui-spacing-4, 16px);
              grid-template-columns: 1fr;
            }
            @media (min-width: 768px) {
              .dashboard-grid {
                grid-template-columns: repeat(3, 1fr);
              }
            }
            @keyframes ggui-pulse {
              0%, 100% { opacity: 1; transform: scale(1); }
              50% { opacity: 0.5; transform: scale(0.9); }
            }
          `}</style>

          <div className="dashboard-grid">
            {currentStocks.length > 0 ? (
              currentStocks.map((stock, idx) => renderStockCard(stock, idx))
            ) : (
              <div style={{ gridColumn: '1 / -1' }}>
                <Card padding={48}>
                  <Stack align="center" justify="center" gap={16}>
                    <Icon name="search" size={48} color="var(--ggui-color-outline, #d4d4d8)" />
                    <Stack align="center" gap={4}>
                      <Text variant="h3" weight="semibold">No Market Data</Text>
                      <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Awaiting connection to the exchange feed...
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              </div>
            )}
          </div>
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Select, Checkbox, RadioGroup, Button, Divider, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  onComplete?: (data: any) => void;
}

export default function OnboardingWizard({ avatarOptions, roleOptions, initialProfile = {}, onComplete }: Props) {
  const [step, setStep] = useState(0);
  const [data, setData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile.role || (roleOptions && roleOptions[0]) || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light',
  });

  const { motionEnabled } = useMotion();
  const update = (key: string, val: any) => setData(p => ({ ...p, [key]: val }));
  const isValidEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const canGoNext = data.name.trim() !== '' && isValidEmail(data.email);

  const progress = ((step + 1) / 3) * 100;

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card padding={24} shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="h2" align="center">Setup</Text>
            <div style={{ height: 4, width: '100%', background: 'var(--ggui-color-outlineVariant)', borderRadius: 2 }}>
              <div style={{ height: '100%', width: `${progress}%`, background: 'var(--ggui-color-primary-600)', borderRadius: 2, transition: transition.normal }} />
            </div>
          </Stack>

          <div style={{ minHeight: 320 }}>
            {step === 0 && (
              <Stack gap={16} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Profile</Text>
                <Input label="Name" value={data.name} onChange={(v) => update('name', v)} required />
                <Input label="Email" type="email" value={data.email} onChange={(v) => update('email', v)} required />
                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  <Row gap={8} wrap>
                    {avatarOptions && avatarOptions.map((emoji) => (
                      <button key={emoji} onClick={() => update('avatar', emoji)} style={{ fontSize: 24, padding: 12, borderRadius: 8, border: `2px solid ${data.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`, background: data.avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)', cursor: 'pointer' }}>{emoji}</button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={16} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Preferences</Text>
                <Select label="Role" value={data.role} onChange={(v) => update('role', v)} options={roleOptions ? roleOptions.map(r => ({ value: r, label: r })) : []} />
                <Checkbox label="Notifications" description="Email updates" checked={data.emailNotifications} onChange={(v) => update('emailNotifications', v)} />
                <RadioGroup label="Theme" value={data.theme} onChange={(v) => update('theme', v)} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Review</Text>
                <Card border padding={16} background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={12}>
                    <Row align="center" gap={12}>
                      <Text style={{ fontSize: 40 }}>{data.avatar}</Text>
                      <Stack gap={0}>
                        <Text weight="bold">{data.name}</Text>
                        <Text variant="caption">{data.email}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Row justify="between"><Text variant="caption">Role</Text><Text variant="caption">{data.role}</Text></Row>
                    <Row justify="between"><Text variant="caption">Theme</Text><Text variant="caption" style={{ textTransform: 'capitalize' }}>{data.theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Row justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 0}>Back</Button>
            {step < 2 ? (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={step === 0 && !canGoNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete && onComplete(data)}>Complete Setup</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}
